    24→// ResponsiveList differs from List in that it enables clients to
    25→// set the min width and height of the children components by using a push
    26→// API with Responsive components, rather than tui.Components.
    27→//
    28→// It also seeks in rows rather than elements, so long elements
    29→// greater than height can be seeked top to bottom, one row at a time.
    30→//
    31→// Alignment responds to AlignmentTop or AlignmentBottom for
    32→// content alignment.
    33→type ResponsiveList struct {
    34→	Alignment
    35→
    36→	list List
    37→
    38→	// in number of rows
    39→	totalHeight int
    40→	offset      int
    41→
    42→	// cannot be used directly here otherwise we would need to somehow
    43→	// override ListNode to also set true this ResponsiveList's
    44→	// returned ListNode, to set dirty on SetValue
    45→	// dirty bool
    46→}
    47→
    48→// NewResponsiveList allocates storage for a new ResponsiveList and initializes it.
    49→func NewResponsiveList() (l *ResponsiveList) {
    50→	l = new(ResponsiveList)
    51→	l.Init()
    52→	return
    53→}
    54→
    55→// Init initializes this list. It can be used to reset its internal state.
    56→func (l *ResponsiveList) Init() {
    57→	l.Reset()
    58→	l.list.Init(1)
    59→}
    60→
    61→// Reset resets the contents of this List.
    62→func (l *ResponsiveList) Reset() {
    63→	l.list.Reset()
    64→	l.offset = 0
    65→	l.totalHeight = 0
    66→	l.list.dirty = true
    67→}
    68→
    69→// PushBackList inserts a copy of an other list at the back of list l. The
    70→// lists l and other must NOT be the same or nil.
    71→func (l *ResponsiveList) PushBackList(other *ResponsiveList) {
    72→	if l == other {
    73→		panic("other list cannot be self: components can't be deep cloned")
    74→	}
    75→	other.Iterate(func(c Responsive) {
