	"github.com/unstablebuild/rune-go-sdk/term"
	"github.com/unstablebuild/tcell/v3"
)

// Config defines the styling options for markdown rendering.
type Config struct {
	// Header styles (H1-H6)
	H1, H2, H3, H4, H5, H6 term.Attributes

	// Text styles
	Paragraph     term.Attributes
	Bold          term.Attributes
	Italic        term.Attributes
	Strikethrough term.Attributes

	// Code styles
	CodeBlock  term.Attributes
	InlineCode term.Attributes

	// Link styles
	Link    term.Attributes
	LinkURL term.Attributes

	// Blockquote styling
	Blockquote       term.Attributes
	BlockquoteBorder rune

	// List styling
	ListBullet        rune
	TaskListChecked   rune
	TaskListUnchecked rune

	// Table styling
	TableCharSet TableCharSet

	// Horizontal rule styling
	HorizontalRule     rune
	HorizontalRuleAttr term.Attributes

	// Spacing
	ParagraphSpacing int
}

// TableCharSet defines the characters used to draw table borders.
type TableCharSet struct {
	component.FrameCharSet
	HeaderSeparator rune
	ColumnSeparator rune
	CrossJoin       rune
	LeftJoin        rune
	RightJoin       rune
}

// DefaultTableCharSet returns the default table character set.
func DefaultTableCharSet() TableCharSet {
	return TableCharSet{
		FrameCharSet:    component.FrameCharSetDefault(),
		HeaderSeparator: '─',
		ColumnSeparator: '│',
		CrossJoin:       '┼',
		LeftJoin:        '├',
		RightJoin:       '┤',
	}
}

// DefaultConfig returns a Config with sensible defaults for terminal rendering.
func DefaultConfig() Config {
	magenta := term.Attributes(tcell.StyleDefault.Foreground(tcell.ColorPurple))
	cyan := term.Attributes(tcell.StyleDefault.Foreground(tcell.ColorTeal))
	yellow := term.Attributes(tcell.StyleDefault.Foreground(tcell.ColorYellow))
	gray := term.Attributes(tcell.StyleDefault.Foreground(tcell.ColorGray))
	white := term.Attributes(tcell.StyleDefault.Foreground(tcell.ColorWhite))
	dimWhite := term.Attributes(tcell.StyleDefault.Foreground(tcell.ColorDimGray))

	return Config{
		H1: term.Attributes(tcell.Style(magenta).Bold()),
		H2: term.Attributes(tcell.Style(magenta).Bold()),
		H3: term.Attributes(tcell.Style(magenta).Bold()),
		H4: magenta,
		H5: magenta,
		H6: magenta,

		Paragraph:     white,
		Bold:          term.Attributes(tcell.Style(white).Bold()),
		Italic:        term.Attributes(tcell.Style(white).Italic()),
		Strikethrough: term.Attributes(tcell.Style(dimWhite).StrikeThrough()),

		CodeBlock:  yellow,
		InlineCode: yellow,

		Link:    term.Attributes(tcell.Style(cyan).Underline()),
		LinkURL: cyan,

		Blockquote:       dimWhite,
		BlockquoteBorder: '│',

		ListBullet:        '•',
		TaskListChecked:   '☑',
		TaskListUnchecked: '☐',

		TableCharSet: DefaultTableCharSet(),

		HorizontalRule:     '─',
		HorizontalRuleAttr: gray,

		ParagraphSpacing: 1,
	}
}

