package markdown

import (
	"strings"
	"unicode"
)

// wrapTextRun wraps a TextRun to fit within the given width.
// Returns the wrapped lines as a slice of TextRuns.
func wrapTextRun(run TextRun, width int) []TextRun {
	if width <= 0 {
		return nil
	}

	var lines []TextRun
	var currentLine TextRun
	var currentWidth int

	for _, span := range run {
		words := splitIntoWords(span.Text)
		for _, word := range words {
			wordLen := len(word)

			if currentWidth > 0 && currentWidth+wordLen > width {
				lines = append(lines, currentLine)
				currentLine = nil
				currentWidth = 0
			}

			if wordLen > width {
				for len(word) > 0 {
					remaining := width - currentWidth
					if remaining <= 0 {
						if len(currentLine) > 0 {
							lines = append(lines, currentLine)
						}
						currentLine = nil
						currentWidth = 0
						remaining = width
					}
					chunk := word
					if len(chunk) > remaining {
						chunk = word[:remaining]
					}
					currentLine = append(currentLine, Span{
						Text:  chunk,
						Style: span.Style,
						URL:   span.URL,
					})
					currentWidth += len(chunk)
					word = word[len(chunk):]
				}
			} else {
				currentLine = append(currentLine, Span{
					Text:  word,
					Style: span.Style,
					URL:   span.URL,
				})
				currentWidth += wordLen
			}
