type ListItem struct {
	Content TextRun
	IsTask  bool
	Checked bool
	Nested  *ListBlock
}

// ListBlock represents a markdown list (ordered or unordered).
type ListBlock struct {
	Ordered bool
	Start   int
	Items   []ListItem
}

var _ Block = (*ListBlock)(nil)

// Height returns the number of rows this list will occupy.
func (l *ListBlock) Height(width int) int {
	return l.heightAtIndent(width, 0)
}

func (l *ListBlock) heightAtIndent(width, indent int) int {
	if width <= indent+listIndent {
		return 0
	}

	height := 0
	effectiveWidth := width - indent - listIndent

	for _, item := range l.Items {
		lines := countWrappedLines(item.Content, effectiveWidth)
		height += lines

		if item.Nested != nil {
			height += item.Nested.heightAtIndent(width, indent+listIndent)
		}
	}

	return height + 1
}

// Render draws the list to the writer.
func (l *ListBlock) Render(w term.Writer, y, width int, cfg *Config) int {
	return l.renderAtIndent(w, y, width, 0, cfg)
}

func (l *ListBlock) renderAtIndent(
	w term.Writer, y, width, indent int, cfg *Config,
) int {
	if width <= indent+listIndent {
		return 0
	}

	startY := y
	effectiveWidth := width - indent - listIndent

	for i, item := range l.Items {
		bullet := l.getBullet(i, item, cfg)

		for j, r := range bullet {
			w.SetCell(term.Coordinates{X: indent + j, Y: y}, term.Cell{
				Ch:         r,
				Width:      1,
				Attributes: cfg.Paragraph,
			})
		}

		lines := wrapTextRun(item.Content, effectiveWidth)
		for lineIdx, line := range lines {
			x := indent + listIndent
			for _, span := range line {
				attr := resolveStyle(span.Style, cfg)
				for _, r := range span.Text {
					if x >= width {
						break
					}
					w.SetCell(term.Coordinates{X: x, Y: y + lineIdx}, term.Cell{
						Ch:         r,
						Width:      1,
						Attributes: attr,
					})
					x++
				}
			}
		}
		y += len(lines)
		if len(lines) == 0 {
			y++
		}

		if item.Nested != nil {
			y += item.Nested.renderAtIndent(w, y, width, indent+listIndent, cfg)
		}
	}

	return y - startY + 1
}

func (l *ListBlock) getBullet(index int, item ListItem, cfg *Config) string {
	if item.IsTask {
		if item.Checked {
			return string(cfg.TaskListChecked) + " "
		}
		return string(cfg.TaskListUnchecked) + " "
	}

	if l.Ordered {
		return fmt.Sprintf("%d.", l.Start+index)
	}

	return string(cfg.ListBullet) + " "
}

