}

func (b *BlockquoteBlock) heightAtIndent(width, indent int) int {
	if width <= indent+blockquoteIndent {
		return 0
	}

	height := 0
	effectiveWidth := width - indent - blockquoteIndent

	for _, content := range b.Content {
		lines := countWrappedLines(content, effectiveWidth)
		height += lines
	}

	if b.Nested != nil {
		height += b.Nested.heightAtIndent(width, indent+blockquoteIndent)
	}

	return height + 1
}

// Render draws the blockquote to the writer.
func (b *BlockquoteBlock) Render(w term.Writer, y, width int, cfg *Config) int {
	return b.renderAtIndent(w, y, width, 0, cfg)
}

