// TableAlignment represents the alignment of a table column.
type TableAlignment int

const (
	AlignLeft TableAlignment = iota
	AlignCenter
	AlignRight
)

// TableBlock represents a markdown table.
type TableBlock struct {
	Header     []TextRun
	Rows       [][]TextRun
	Alignments []TableAlignment
}

var _ Block = (*TableBlock)(nil)

// Height returns the number of rows this table will occupy.
func (t *TableBlock) Height(width int) int {
	if width <= 0 || len(t.Header) == 0 {
		return 0
	}
	return len(t.Rows) + 3
}

// Render draws the table to the writer.
func (t *TableBlock) Render(w term.Writer, y, width int, cfg *Config) int {
	if width <= 0 || len(t.Header) == 0 {
		return 0
	}

	numCols := len(t.Header)
	colWidths := t.calculateColumnWidths(width, numCols)
	cs := cfg.TableCharSet

	y = t.renderHeaderRow(w, y, colWidths, cs, cfg)
	y = t.renderSeparator(w, y, colWidths, cs, cfg)
	for _, row := range t.Rows {
		y = t.renderDataRow(w, y, row, colWidths, cs, cfg)
	}

	return len(t.Rows) + 3
}

func (t *TableBlock) calculateColumnWidths(totalWidth, numCols int) []int {
	if numCols == 0 {
		return nil
	}
	availableWidth := totalWidth - (numCols + 1)
	baseWidth := availableWidth / numCols
	remainder := availableWidth % numCols

	widths := make([]int, numCols)
	for i := range widths {
		widths[i] = baseWidth
		if i < remainder {
			widths[i]++
		}
		if widths[i] < 1 {
			widths[i] = 1
		}
	}
	return widths
}

func (t *TableBlock) renderHeaderRow(
	w term.Writer, y int, colWidths []int, cs TableCharSet, cfg *Config,
) int {
	x := 0
	w.SetCell(term.Coordinates{X: x, Y: y}, term.Cell{
		Ch:         cs.ColumnSeparator,
		Width:      1,
		Attributes: cfg.Paragraph,
	})
	x++

	for i, cell := range t.Header {
		if i >= len(colWidths) {
			break
		}
		colWidth := colWidths[i]
		t.renderCell(w, x, y, colWidth, cell, t.getAlignment(i), cfg, true)
		x += colWidth

		w.SetCell(term.Coordinates{X: x, Y: y}, term.Cell{
			Ch:         cs.ColumnSeparator,
			Width:      1,
			Attributes: cfg.Paragraph,
		})
		x++
	}
	return y + 1
}

func (t *TableBlock) renderSeparator(
	w term.Writer, y int, colWidths []int, cs TableCharSet, cfg *Config,
) int {
	x := 0

	w.SetCell(term.Coordinates{X: x, Y: y}, term.Cell{
		Ch:         cs.LeftJoin,
		Width:      1,
		Attributes: cfg.Paragraph,
	})
	x++

	for i, colWidth := range colWidths {
		for j := 0; j < colWidth; j++ {
			w.SetCell(term.Coordinates{X: x + j, Y: y}, term.Cell{
				Ch:         cs.HeaderSeparator,
				Width:      1,
				Attributes: cfg.Paragraph,
			})
		}
		x += colWidth

		ch := cs.CrossJoin
		if i == len(colWidths)-1 {
			ch = cs.RightJoin
		}
		w.SetCell(term.Coordinates{X: x, Y: y}, term.Cell{
			Ch:         ch,
			Width:      1,
			Attributes: cfg.Paragraph,
		})
		x++
	}
	return y + 1
}

func (t *TableBlock) renderDataRow(
	w term.Writer, y int, row []TextRun, colWidths []int, cs TableCharSet, cfg *Config,
) int {
	x := 0
	w.SetCell(term.Coordinates{X: x, Y: y}, term.Cell{
		Ch:         cs.ColumnSeparator,
		Width:      1,
		Attributes: cfg.Paragraph,
	})
	x++

	for i := 0; i < len(colWidths); i++ {
		colWidth := colWidths[i]
		var cell TextRun
		if i < len(row) {
			cell = row[i]
		}
		t.renderCell(w, x, y, colWidth, cell, t.getAlignment(i), cfg, false)
		x += colWidth

		w.SetCell(term.Coordinates{X: x, Y: y}, term.Cell{
			Ch:         cs.ColumnSeparator,
			Width:      1,
			Attributes: cfg.Paragraph,
		})
		x++
	}
	return y + 1
}

func (t *TableBlock) renderCell(
	w term.Writer, x, y, width int, content TextRun,
	align TableAlignment, cfg *Config, isHeader bool,
) {
	text := content.String()
	textLen := len(text)
	if textLen > width {
		text = text[:width]
		textLen = width
	}

	var padding int
	switch align {
	case AlignCenter:
		padding = (width - textLen) / 2
	case AlignRight:
		padding = width - textLen
	}

	attr := cfg.Paragraph
	if isHeader {
		attr = cfg.Bold
	}

	spanIdx := 0
	runeIdx := 0
	for i, r := range text {
		cellX := x + padding + i
		cellAttr := attr
		if spanIdx < len(content) {
			span := content[spanIdx]
			if !isHeader {
				cellAttr = resolveStyle(span.Style, cfg)
			}
			runeIdx++
			if runeIdx >= len(span.Text) {
				spanIdx++
				runeIdx = 0
			}
		}
		w.SetCell(term.Coordinates{X: cellX, Y: y}, term.Cell{
			Ch:         r,
			Width:      1,
			Attributes: cellAttr,
		})
	}
}

func (t *TableBlock) getAlignment(col int) TableAlignment {
	if col < len(t.Alignments) {
		return t.Alignments[col]
	}
	return AlignLeft
}

