			first = false
			continue
		}
		w.walkInlineSingle(child, StyleNone, &run)
	}
	return run
}

func (w *blockWalker) walkInlineSingle(child ast.Node, style InlineStyle, run *TextRun) {
	switch node := child.(type) {
	case *ast.Text:
