func TestHeaderBlockHeight(t *testing.T) {
	tests := []struct {
		name     string
		block    *HeaderBlock
		width    int
		expected int
	}{
		{
			name:     "simple header",
			block:    &HeaderBlock{Level: 1, Content: TextRun{{Text: "Hello"}}},
			width:    20,
			expected: 2,
		},
		{
			name:     "header wraps",
			block:    &HeaderBlock{Level: 1, Content: TextRun{{Text: "Hello World"}}},
			width:    5,
			expected: 3,
		},
		{
			name:     "zero width",
			block:    &HeaderBlock{Level: 1, Content: TextRun{{Text: "Hello"}}},
			width:    0,
			expected: 0,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			assert.Equal(t, tt.expected, tt.block.Height(tt.width))
		})
	}
}

func TestParagraphBlockHeight(t *testing.T) {
	tests := []struct {
		name     string
		block    *ParagraphBlock
		width    int
		expected int
	}{
		{
			name:     "simple paragraph",
			block:    &ParagraphBlock{Content: TextRun{{Text: "Hello"}}},
			width:    20,
			expected: 2,
		},
		{
			name:     "paragraph wraps",
			block:    &ParagraphBlock{Content: TextRun{{Text: "Hello World Test"}}},
			width:    5,
			expected: 4,
		},
		{
			name:     "zero width",
			block:    &ParagraphBlock{Content: TextRun{{Text: "Hello"}}},
			width:    0,
			expected: 0,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			assert.Equal(t, tt.expected, tt.block.Height(tt.width))
		})
	}
}

func TestCodeBlockHeight(t *testing.T) {
	tests := []struct {
		name     string
		block    *CodeBlock
		width    int
		expected int
	}{
		{
			name:     "single line",
			block:    &CodeBlock{Code: "code"},
			width:    20,
			expected: 2,
		},
		{
			name:     "multiple lines",
			block:    &CodeBlock{Code: "line1\nline2\nline3"},
			width:    20,
			expected: 4,
		},
		{
			name:     "trailing newline",
			block:    &CodeBlock{Code: "code\n"},
			width:    20,
			expected: 2,
		},
		{
			name:     "zero width",
			block:    &CodeBlock{Code: "code"},
			width:    0,
			expected: 0,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			assert.Equal(t, tt.expected, tt.block.Height(tt.width))
		})
	}
}

