		width    int
		expected int
	}{
		{
			name: "simple list",
			block: &ListBlock{
				Items: []ListItem{
					{Content: TextRun{{Text: "Item 1"}}},
					{Content: TextRun{{Text: "Item 2"}}},
				},
			},
			width:    20,
			expected: 3,
		},
		{
			name: "nested list",
			block: &ListBlock{
				Items: []ListItem{
					{
						Content: TextRun{{Text: "Item 1"}},
						Nested: &ListBlock{
							Items: []ListItem{
								{Content: TextRun{{Text: "Nested"}}},
							},
						},
					},
				},
			},
			width:    20,
			expected: 3,
		},
		{
			name:     "zero width",
			block:    &ListBlock{Items: []ListItem{{Content: TextRun{{Text: "Item"}}}}},
			width:    0,
			expected: 0,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
