func TestBlockRender(t *testing.T) {
	cfg := DefaultConfig()
	w := term.NewStringWriter(20, 10)

	tests := []struct {
		name     string
		block    Block
		expected int
	}{
		{
			name:     "header",
			block:    &HeaderBlock{Level: 1, Content: TextRun{{Text: "Title"}}},
			expected: 2,
		},
		{
			name:     "paragraph",
			block:    &ParagraphBlock{Content: TextRun{{Text: "Text"}}},
			expected: 2,
		},
		{
			name:     "code",
			block:    &CodeBlock{Code: "code"},
			expected: 2,
		},
		{
			name:     "hrule",
			block:    &HorizontalRuleBlock{},
			expected: 2,
		},
		{
			name:     "list",
			block:    &ListBlock{Items: []ListItem{{Content: TextRun{{Text: "Item"}}}}},
			expected: 2,
		},
		{
			name:     "blockquote",
			block:    &BlockquoteBlock{Content: []TextRun{{{Text: "Quote"}}}},
			expected: 2,
		},
		{
			name: "table",
			block: &TableBlock{
				Header: []TextRun{{{Text: "A"}}},
				Rows:   [][]TextRun{{{{Text: "1"}}}},
			},
			expected: 4,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			require.NoError(t, w.Clear(term.Attributes{}))
			rendered := tt.block.Render(w, 0, 20, &cfg)
			assert.Equal(t, tt.expected, rendered)
		})
	}
}

func TestTextRunString(t *testing.T) {
	tests := []struct {
		name     string
		run      TextRun
		expected string
	}{
		{
			name:     "empty",
			run:      TextRun{},
			expected: "",
		},
		{
			name:     "single span",
			run:      TextRun{{Text: "hello"}},
			expected: "hello",
		},
		{
			name:     "multiple spans",
			run:      TextRun{{Text: "hello "}, {Text: "world"}},
			expected: "hello world",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			assert.Equal(t, tt.expected, tt.run.String())
		})
	}
}

func TestTextRunLen(t *testing.T) {
	tests := []struct {
		name     string
		run      TextRun
		expected int
	}{
		{
			name:     "empty",
			run:      TextRun{},
			expected: 0,
		},
		{
			name:     "single span",
			run:      TextRun{{Text: "hello"}},
			expected: 5,
		},
		{
			name:     "multiple spans",
			run:      TextRun{{Text: "hello"}, {Text: "world"}},
			expected: 10,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			assert.Equal(t, tt.expected, tt.run.Len())
		})
	}
}

func TestWrapTextRun(t *testing.T) {
	tests := []struct {
		name          string
		run           TextRun
		width         int
		expectedLines int
	}{
		{
			name:          "fits in width",
			run:           TextRun{{Text: "hello"}},
			width:         10,
			expectedLines: 1,
		},
		{
			name:          "wraps at word boundary",
			run:           TextRun{{Text: "hello world"}},
			width:         6,
			expectedLines: 2,
		},
		{
			name:          "breaks long word",
			run:           TextRun{{Text: "superlongword"}},
			width:         5,
			expectedLines: 3,
		},
		{
			name:          "zero width",
			run:           TextRun{{Text: "hello"}},
			width:         0,
			expectedLines: 0,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			lines := wrapTextRun(tt.run, tt.width)
			assert.Len(t, lines, tt.expectedLines)
		})
	}
}

