// renderTextRun draws a TextRun starting at position (x, y).
// Returns the final x position after rendering.
func renderTextRun(
	w term.Writer, run TextRun, x, y, width int, cfg *Config,
) int {
	for _, span := range run {
		attr := resolveStyle(span.Style, cfg)
		for _, r := range span.Text {
			if x >= width {
				break
			}
			w.SetCell(term.Coordinates{X: x, Y: y}, term.Cell{
				Ch:         r,
				Width:      1,
				Attributes: attr,
			})
			x++
		}
	}
