// wrapTextRun wraps a TextRun to fit within the given width.
// Returns the wrapped lines as a slice of TextRuns.
func wrapTextRun(run TextRun, width int) []TextRun {
	if width <= 0 {
		return nil
	}

	var lines []TextRun
	var currentLine TextRun
	var currentWidth int

	for _, span := range run {
		words := splitIntoWords(span.Text)
		for _, word := range words {
			wordLen := len(word)

			if currentWidth > 0 && currentWidth+wordLen > width {
				lines = append(lines, currentLine)
				currentLine = nil
				currentWidth = 0
			}

			if wordLen > width {
				for len(word) > 0 {
					remaining := width - currentWidth
					if remaining <= 0 {
						if len(currentLine) > 0 {
							lines = append(lines, currentLine)
						}
						currentLine = nil
						currentWidth = 0
						remaining = width
					}
					chunk := word
					if len(chunk) > remaining {
						chunk = word[:remaining]
					}
					currentLine = append(currentLine, Span{
						Text:  chunk,
						Style: span.Style,
						URL:   span.URL,
					})
					currentWidth += len(chunk)
					word = word[len(chunk):]
				}
			} else {
				currentLine = append(currentLine, Span{
					Text:  word,
					Style: span.Style,
					URL:   span.URL,
				})
				currentWidth += wordLen
			}
		}
	}

	if len(currentLine) > 0 {
		lines = append(lines, currentLine)
	}

	return lines
}

// splitIntoWords splits text into words, preserving spaces as part of the
// following word when they occur between words.
func splitIntoWords(text string) []string {
	var words []string
	var current strings.Builder
	var leadingSpace bool

	for _, r := range text {
		if unicode.IsSpace(r) {
			if current.Len() > 0 {
				words = append(words, current.String())
				current.Reset()
			}
			leadingSpace = true
		} else {
			if leadingSpace && len(words) > 0 {
				current.WriteRune(' ')
			}
			leadingSpace = false
			current.WriteRune(r)
		}
	}

	if current.Len() > 0 {
		words = append(words, current.String())
	}

	return words
}

// countWrappedLines returns the number of lines needed to display the run.
func countWrappedLines(run TextRun, width int) int {
	if width <= 0 {
		return 0
	}
	lines := wrapTextRun(run, width)
	if len(lines) == 0 {
		return 1
	}
	return len(lines)
