func TestHeaderBlockHeight(t *testing.T) {
	tests := []struct {
		name     string
		block    *HeaderBlock
		width    int
		expected int
	}{
		{
			name:     "simple header",
			block:    &HeaderBlock{Level: 1, Content: TextRun{{Text: "Hello"}}},
			width:    20,
			expected: 2,
		},
		{
			name:     "header wraps",
			block:    &HeaderBlock{Level: 1, Content: TextRun{{Text: "Hello World"}}},
			width:    5,
			expected: 4,
		},
		{
			name:     "zero width",
			block:    &HeaderBlock{Level: 1, Content: TextRun{{Text: "Hello"}}},
			width:    0,
			expected: 0,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			assert.Equal(t, tt.expected, tt.block.Height(tt.width))
		})
	}
}

