    17→// RemoveFrontmatter removes the front matter header of a markdown file.
    18→func RemoveFrontmatter(content []byte) []byte {
    19→	if frontmatterBoundaries := detectFrontmatter(content); frontmatterBoundaries[0] == 0 {
    20→		return content[frontmatterBoundaries[1]:]
    21→	}
    22→	return content
    23→}
    24→
    25→var yamlPattern = regexp.MustCompile(`(?m)^---\r?\n(\s*\r?\n)?`)
    26→
    27→func detectFrontmatter(c []byte) []int {
    28→	if matches := yamlPattern.FindAllIndex(c, 2); len(matches) > 1 {
    29→		return []int{matches[0][0], matches[1][1]}
    30→	}
    31→	return []int{-1, -1}
    32→}
