    34→// ExpandPath expands tilde and all environment variables from the given path.
    35→func ExpandPath(path string) string {
    36→	s, err := homedir.Expand(path)
    37→	if err == nil {
    38→		return os.ExpandEnv(s)
    39→	}
    40→	return os.ExpandEnv(path)
    41→}
    42→
    43→// WrapCodeBlock wraps a string in a code block with the given language.
    44→func WrapCodeBlock(s, language string) string {
    45→	return "```" + language + "\n" + s + "```"
