    47→
    48→var markdownExtensions = []string{
    49→	".md", ".mdown", ".mkdn", ".mkd", ".markdown",
    50→}
    51→
    52→// IsMarkdownFile returns whether the filename has a markdown extension.
    53→func IsMarkdownFile(filename string) bool {
    54→	ext := filepath.Ext(filename)
    55→
    56→	if ext == "" {
    57→		// By default, assume it's a markdown file.
    58→		return true
    59→	}
    60→
    61→	for _, v := range markdownExtensions {
    62→		if strings.EqualFold(ext, v) {
    63→			return true
    64→		}
    65→	}
    66→
    67→	// Has an extension but not markdown
    68→	// so assume this is a code file.
    69→	return false
    70→}
    71→
    72→// GlamourStyle returns a glamour.TermRendererOption based on the given style.
    73→func GlamourStyle(style string, isCode bool) glamour.TermRendererOption {
    74→	if !isCode {
    75→		if style == styles.AutoStyle {
    76→			return glamour.WithAutoStyle()
    77→		}
    78→		return glamour.WithStylePath(style)
    79→	}
    80→
    81→	// If we are rendering a pure code block, we need to modify the style to
    82→	// remove the indentation.
    83→
    84→	var styleConfig ansi.StyleConfig
    85→
    86→	switch style {
    87→	case styles.AutoStyle:
    88→		if lipgloss.HasDarkBackground() {
    89→			styleConfig = styles.DarkStyleConfig
    90→		} else {
    91→			styleConfig = styles.LightStyleConfig
    92→		}
    93→	case styles.DarkStyle:
    94→		styleConfig = styles.DarkStyleConfig
    95→	case styles.LightStyle:
    96→		styleConfig = styles.LightStyleConfig
    97→	case styles.PinkStyle:
    98→		styleConfig = styles.PinkStyleConfig
    99→	case styles.NoTTYStyle:
