   101→	case styles.DraculaStyle:
   102→		styleConfig = styles.DraculaStyleConfig
   103→	case styles.TokyoNightStyle:
   104→		styleConfig = styles.DraculaStyleConfig
   105→	default:
   106→		return glamour.WithStylesFromJSONFile(style)
   107→	}
   108→
