    15→	emoji "github.com/yuin/goldmark-emoji"
    16→	"github.com/yuin/goldmark/extension"
    17→	"github.com/yuin/goldmark/parser"
    18→	"github.com/yuin/goldmark/renderer"
    19→	"github.com/yuin/goldmark/util"
    20→	"golang.org/x/term"
    21→
    22→	"github.com/charmbracelet/glamour/ansi"
    23→	styles "github.com/charmbracelet/glamour/styles"
    24→)
    25→
    26→const (
    27→	defaultWidth = 80
    28→	highPriority = 1000
    29→)
    30→
    31→// A TermRendererOption sets an option on a TermRenderer.
    32→type TermRendererOption func(*TermRenderer) error
    33→
    34→// TermRenderer can be used to render markdown content, posing a depth of
    35→// customization and styles to fit your needs.
    36→type TermRenderer struct {
    37→	md          goldmark.Markdown
    38→	ansiOptions ansi.Options
    39→	buf         bytes.Buffer
    40→	renderBuf   bytes.Buffer
    41→}
    42→
    43→// Render initializes a new TermRenderer and renders a markdown with a specific
    44→// style.
    45→func Render(in string, stylePath string) (string, error) {
    46→	b, err := RenderBytes([]byte(in), stylePath)
    47→	return string(b), err
    48→}
    49→
    50→// RenderWithEnvironmentConfig initializes a new TermRenderer and renders a
    51→// markdown with a specific style defined by the GLAMOUR_STYLE environment variable.
    52→func RenderWithEnvironmentConfig(in string) (string, error) {
    53→	b, err := RenderBytes([]byte(in), getEnvironmentStyle())
    54→	return string(b), err
    55→}
    56→
    57→// RenderBytes initializes a new TermRenderer and renders a markdown with a
    58→// specific style.
    59→func RenderBytes(in []byte, stylePath string) ([]byte, error) {
    60→	r, err := NewTermRenderer(
    61→		WithStylePath(stylePath),
    62→	)
    63→	if err != nil {
    64→		return nil, err
    65→	}
    66→	return r.RenderBytes(in)
    67→}
    68→
    69→// NewTermRenderer returns a new TermRenderer the given options.
    70→func NewTermRenderer(options ...TermRendererOption) (*TermRenderer, error) {
    71→	tr := &TermRenderer{
    72→		md: goldmark.New(
    73→			goldmark.WithExtensions(
    74→				extension.GFM,
    75→				extension.DefinitionList,
    76→			),
    77→			goldmark.WithParserOptions(
    78→				parser.WithAutoHeadingID(),
    79→			),
    80→		),
    81→		ansiOptions: ansi.Options{
    82→			WordWrap:     defaultWidth,
    83→			ColorProfile: termenv.TrueColor,
    84→		},
    85→	}
    86→	for _, o := range options {
    87→		if err := o(tr); err != nil {
    88→			return nil, err
    89→		}
    90→	}
    91→	ar := ansi.NewRenderer(tr.ansiOptions)
    92→	tr.md.SetRenderer(
    93→		renderer.NewRenderer(
    94→			renderer.WithNodeRenderers(
    95→				util.Prioritized(ar, highPriority),
    96→			),
    97→		),
    98→	)
    99→	return tr, nil
   100→}
   101→
   102→// WithBaseURL sets a TermRenderer's base URL.
   103→func WithBaseURL(baseURL string) TermRendererOption {
   104→	return func(tr *TermRenderer) error {
   105→		tr.ansiOptions.BaseURL = baseURL
   106→		return nil
   107→	}
   108→}
   109→
   110→// WithColorProfile sets the TermRenderer's color profile
   111→// (TrueColor / ANSI256 / ANSI).
   112→func WithColorProfile(profile termenv.Profile) TermRendererOption {
   113→	return func(tr *TermRenderer) error {
   114→		tr.ansiOptions.ColorProfile = profile
   115→		return nil
   116→	}
   117→}
   118→
   119→// WithStandardStyle sets a TermRenderer's styles with a standard (builtin)
   120→// style.
   121→func WithStandardStyle(style string) TermRendererOption {
   122→	return func(tr *TermRenderer) error {
   123→		styles, err := getDefaultStyle(style)
   124→		if err != nil {
   125→			return err
   126→		}
   127→		tr.ansiOptions.Styles = *styles
   128→		return nil
   129→	}
   130→}
   131→
   132→// WithAutoStyle sets a TermRenderer's styles with either the standard dark
   133→// or light style, depending on the terminal's background color at run-time.
   134→func WithAutoStyle() TermRendererOption {
   135→	return WithStandardStyle(styles.AutoStyle)
   136→}
   137→
   138→// WithEnvironmentConfig sets a TermRenderer's styles based on the
   139→// GLAMOUR_STYLE environment variable.
   140→func WithEnvironmentConfig() TermRendererOption {
   141→	return WithStylePath(getEnvironmentStyle())
   142→}
   143→
   144→// WithStylePath sets a TermRenderer's style from stylePath. stylePath is first
   145→// interpreted as a filename. If no such file exists, it is re-interpreted as a
   146→// standard style.
   147→func WithStylePath(stylePath string) TermRendererOption {
   148→	return func(tr *TermRenderer) error {
   149→		styles, err := getDefaultStyle(stylePath)
   150→		if err != nil {
   151→			jsonBytes, err := os.ReadFile(stylePath)
   152→			if err != nil {
   153→				return fmt.Errorf("glamour: error reading file: %w", err)
   154→			}
   155→
   156→			return json.Unmarshal(jsonBytes, &tr.ansiOptions.Styles)
   157→		}
   158→		tr.ansiOptions.Styles = *styles
   159→		return nil
   160→	}
   161→}
   162→
   163→// WithStyles sets a TermRenderer's styles.
   164→func WithStyles(styles ansi.StyleConfig) TermRendererOption {
   165→	return func(tr *TermRenderer) error {
   166→		tr.ansiOptions.Styles = styles
   167→		return nil
   168→	}
   169→}
   170→
   171→// WithStylesFromJSONBytes sets a TermRenderer's styles by parsing styles from
   172→// jsonBytes.
   173→func WithStylesFromJSONBytes(jsonBytes []byte) TermRendererOption {
   174→	return func(tr *TermRenderer) error {
   175→		return json.Unmarshal(jsonBytes, &tr.ansiOptions.Styles)
   176→	}
   177→}
   178→
   179→// WithStylesFromJSONFile sets a TermRenderer's styles from a JSON file.
   180→func WithStylesFromJSONFile(filename string) TermRendererOption {
   181→	return func(tr *TermRenderer) error {
   182→		jsonBytes, err := os.ReadFile(filename)
   183→		if err != nil {
   184→			return fmt.Errorf("glamour: error reading file: %w", err)
   185→		}
   186→		return json.Unmarshal(jsonBytes, &tr.ansiOptions.Styles)
   187→	}
   188→}
   189→
   190→// WithWordWrap sets a TermRenderer's word wrap.
   191→func WithWordWrap(wordWrap int) TermRendererOption {
   192→	return func(tr *TermRenderer) error {
   193→		tr.ansiOptions.WordWrap = wordWrap
   194→		return nil
   195→	}
   196→}
   197→
   198→// WithTableWrap controls whether table content will wrap if too long.
   199→// This is true by default. If false, table content will be truncated with an
   200→// ellipsis if too long to fit.
   201→func WithTableWrap(tableWrap bool) TermRendererOption {
   202→	return func(tr *TermRenderer) error {
   203→		tr.ansiOptions.TableWrap = &tableWrap
   204→		return nil
   205→	}
   206→}
   207→
   208→// WithInlineTableLinks forces tables to render links inline. By default,links
   209→// are rendered as a list of links at the bottom of the table.
   210→func WithInlineTableLinks(inlineTableLinks bool) TermRendererOption {
   211→	return func(tr *TermRenderer) error {
   212→		tr.ansiOptions.InlineTableLinks = inlineTableLinks
   213→		return nil
   214→	}
   215→}
   216→
   217→// WithPreservedNewLines preserves newlines from being replaced.
   218→func WithPreservedNewLines() TermRendererOption {
   219→	return func(tr *TermRenderer) error {
   220→		tr.ansiOptions.PreserveNewLines = true
   221→		return nil
   222→	}
   223→}
   224→
   225→// WithEmoji sets a TermRenderer's emoji rendering.
   226→func WithEmoji() TermRendererOption {
   227→	return func(tr *TermRenderer) error {
   228→		emoji.New().Extend(tr.md)
   229→		return nil
   230→	}
   231→}
   232→
   233→// WithChromaFormatter sets a TermRenderer's chroma formatter used for code blocks.
   234→func WithChromaFormatter(formatter string) TermRendererOption {
   235→	return func(tr *TermRenderer) error {
   236→		tr.ansiOptions.ChromaFormatter = formatter
   237→		return nil
   238→	}
   239→}
   240→
   241→// WithOptions sets multiple TermRenderer options within a single TermRendererOption.
   242→func WithOptions(options ...TermRendererOption) TermRendererOption {
   243→	return func(tr *TermRenderer) error {
   244→		for _, o := range options {
   245→			if err := o(tr); err != nil {
   246→				return err
   247→			}
   248→		}
   249→		return nil
   250→	}
   251→}
   252→
   253→func (tr *TermRenderer) Read(b []byte) (int, error) {
   254→	n, err := tr.renderBuf.Read(b)
   255→	if err == io.EOF {
   256→		return n, io.EOF
   257→	}
   258→	if err != nil {
   259→		return 0, fmt.Errorf("glamour: error reading from buffer: %w", err)
   260→	}
   261→	return n, nil
   262→}
   263→
   264→func (tr *TermRenderer) Write(b []byte) (int, error) {
   265→	n, err := tr.buf.Write(b)
   266→	if err != nil {
   267→		return 0, fmt.Errorf("glamour: error writing bytes: %w", err)
   268→	}
   269→	return n, nil
   270→}
   271→
   272→// Close must be called after writing to TermRenderer. You can then retrieve
   273→// the rendered markdown by calling Read.
   274→func (tr *TermRenderer) Close() error {
   275→	err := tr.md.Convert(tr.buf.Bytes(), &tr.renderBuf)
   276→	if err != nil {
   277→		return fmt.Errorf("glamour: error converting markdown: %w", err)
   278→	}
   279→
   280→	tr.buf.Reset()
   281→	return nil
   282→}
   283→
   284→// Render returns the markdown rendered into a string.
   285→func (tr *TermRenderer) Render(in string) (string, error) {
   286→	b, err := tr.RenderBytes([]byte(in))
   287→	return string(b), err
   288→}
   289→
   290→// RenderBytes returns the markdown rendered into a byte slice.
   291→func (tr *TermRenderer) RenderBytes(in []byte) ([]byte, error) {
   292→	var buf bytes.Buffer
   293→	err := tr.md.Convert(in, &buf)
   294→	return buf.Bytes(), err
   295→}
   296→
   297→func getEnvironmentStyle() string {
   298→	glamourStyle := os.Getenv("GLAMOUR_STYLE")
   299→	if len(glamourStyle) == 0 {
   300→		glamourStyle = styles.AutoStyle
   301→	}
   302→
   303→	return glamourStyle
   304→}
   305→
   306→func getDefaultStyle(style string) (*ansi.StyleConfig, error) {
   307→	if style == styles.AutoStyle {
   308→		if !term.IsTerminal(int(os.Stdout.Fd())) {
   309→			return &styles.NoTTYStyleConfig, nil
   310→		}
   311→		if termenv.HasDarkBackground() {
   312→			return &styles.DarkStyleConfig, nil
   313→		}
   314→		return &styles.LightStyleConfig, nil
   315→	}
   316→
   317→	styles, ok := styles.DefaultStyles[style]
   318→	if !ok {
   319→		return nil, fmt.Errorf("%s: style not found", style)
   320→	}
   321→	return styles, nil
   322→}
