    15→package markdown
    16→
    17→import (
    18→	"github.com/unstablebuild/rune-go-sdk/component"
    19→	"github.com/unstablebuild/rune-go-sdk/term"
    20→)
    21→
    22→// Component renders markdown content in a terminal.
    23→// It implements component.ScrollableFloating.
    24→type Component struct {
    25→	blocks []Block
    26→	cfg    Config
    27→
    28→	width, height int
    29→	offset        int
    30→	totalHeight   int
    31→	heightCache   []int
    32→	cacheWidth    int
    33→}
    34→
    35→var _ component.ScrollableFloating = (*Component)(nil)
    36→
    37→// New creates a new markdown component with the given content
    38→// using default styling.
    39→func New(content string) *Component {
    40→	return NewWithConfig(content, DefaultConfig())
    41→}
    42→
    43→// NewWithConfig creates a new markdown component with the given content
    44→// and custom configuration.
    45→func NewWithConfig(content string, cfg Config) *Component {
    46→	blocks, _ := Parse(content)
    47→	return &Component{
    48→		blocks: blocks,
    49→		cfg:    cfg,
    50→	}
    51→}
    52→
    53→// Resize updates the viewport dimensions and recalculates block heights
    54→// if the width has changed.
    55→func (c *Component) Resize(width, height int) {
    56→	c.width, c.height = width, height
    57→	if c.cacheWidth != width {
    58→		c.recalculateHeights()
    59→	}
    60→	if max := c.MaxSeekOffset(); c.offset > max {
    61→		c.offset = max
    62→	}
    63→}
    64→
    65→// Draw renders the visible portion of the markdown content.
    66→func (c *Component) Draw(w term.Writer) {
    67→	if c.width <= 0 || c.height <= 0 {
    68→		return
    69→	}
    70→	w = term.BoundsCheckWriter(c.width, c.height, w)
    71→	y := -c.offset
    72→	for i, block := range c.blocks {
    73→		blockHeight := c.heightCache[i]
    74→		if y+blockHeight <= 0 {
    75→			y += blockHeight
    76→			continue
    77→		}
    78→		if y >= c.height {
    79→			break
    80→		}
    81→		vw := &component.VirtualWriter{
    82→			Writer: w,
    83→			Offset: term.Coordinates{X: 0, Y: y},
    84→			Width:  c.width,
    85→			Height: blockHeight,
    86→		}
    87→		block.Render(vw, 0, c.width, &c.cfg)
    88→		y += blockHeight
    89→	}
    90→}
    91→
    92→// SeekUp scrolls the content up by one row.
    93→// Returns true if scrolling occurred.
    94→func (c *Component) SeekUp() bool {
    95→	if c.offset > 0 {
    96→		c.offset--
    97→		return true
    98→	}
    99→	return false
   100→}
   101→
   102→// SeekDown scrolls the content down by one row.
   103→// Returns true if scrolling occurred.
   104→func (c *Component) SeekDown() bool {
   105→	if c.offset < c.MaxSeekOffset() {
   106→		c.offset++
   107→		return true
   108→	}
   109→	return false
   110→}
   111→
   112→// SeekOffset returns the current scroll offset.
   113→func (c *Component) SeekOffset() int {
   114→	return c.offset
   115→}
   116→
   117→// MaxSeekOffset returns the maximum scroll offset.
   118→func (c *Component) MaxSeekOffset() int {
   119→	if c.totalHeight <= c.height {
   120→		return 0
   121→	}
   122→	return c.totalHeight - c.height
   123→}
   124→
   125→// Dimensions returns the preferred width and total content height.
   126→func (c *Component) Dimensions() (width, height int) {
   127→	return 80, c.totalHeight
   128→}
   129→
   130→func (c *Component) recalculateHeights() {
   131→	c.heightCache = make([]int, len(c.blocks))
   132→	c.totalHeight = 0
   133→	for i, block := range c.blocks {
   134→		h := block.Height(c.width)
   135→		c.heightCache[i] = h
   136→		c.totalHeight += h
   137→	}
   138→	c.cacheWidth = c.width
   139→}
