	md := New("# Hello\n\nWorld")
	md.Resize(40, 5)

	assert.Implements(t, (*interface {
		SeekUp() bool
		SeekDown() bool
		SeekOffset() int
		MaxSeekOffset() int
		Dimensions() (int, int)
	})(nil), md)
}

