    14→
    15→package component
    16→
    17→import (
    18→	"github.com/unstablebuild/rune-go-sdk/term"
    19→	"github.com/unstablebuild/rune-go-sdk/tui"
    20→)
    21→
    22→// FrameUnionCharSet configures the characters used to draw the frame union
    23→// between the top and bottom components.
    24→type FrameUnionCharSet struct {
    25→	FrameCharSet
    26→	Left   rune
    27→	Right  rune
    28→	Top    rune
    29→	Bottom rune
    30→}
    31→
    32→// DefaultFrameUnionCharSet returns the default FrameUnionCharSet used.
    33→func DefaultFrameUnionCharSet() (ret FrameUnionCharSet) {
    34→	ret.FrameCharSet = FrameCharSetDefault()
    35→	ret.Left = '├'
    36→	ret.Right = '┤'
    37→	ret.Top = '┬'
    38→	ret.Bottom = '┴'
    39→	return
    40→}
    41→
    42→// FrameUnion is a tui.Component which Draws a main Component
    43→// at the max available width and height, but otherwise depending on
    44→// how many other statically sized components are stacked either left, right
    45→// top or bottom.
    46→//
    47→// It respects the stacked components height if stacked on top or bottom
    48→// and it respects the stacked components width if stacked left or right.
    49→// The API uses Virtual instead of tui.Component to determine what's the desired
    50→// height or width.
    51→type FrameUnion struct {
    52→	main          Virtual[tui.Component]
    53→	top, bottom   []*frameVirtual
    54→	left, right   []*frameVirtual
    55→	height, width int
    56→
    57→	// Frame determines whether underlying components are an instance of Frame
    58→	// and so FrameUnion should stitch them together with FrameUnionCharSet.
    59→	// Default is true.
    60→	Frame bool
    61→
    62→	// Attributes to be set to FrameUnionCharSet.
    63→	term.Attributes
    64→
    65→	FrameUnionCharSet
    66→}
    67→
    68→// NewFrameUnion allocates storage for a new FrameUnion and initializes it.
    69→func NewFrameUnion(main tui.Component) *FrameUnion {
    70→	ret := new(FrameUnion)
    71→	ret.Init(main)
    72→	return ret
    73→}
    74→
    75→// Init initializes this frame union with main as the main compontent.
    76→func (u *FrameUnion) Init(main tui.Component) {
    77→	u.FrameUnionCharSet = DefaultFrameUnionCharSet()
    78→	u.main.C = main
    79→	u.Frame = true
    80→}
    81→
    82→// UnionTop stacks top on top of the main component. This
    83→// method panics if top is nil.
    84→func (u *FrameUnion) UnionTop(top tui.Component, height int) {
    85→	u.UnionTopFrame(top, height, true)
    86→}
    87→
    88→// UnionTopFrame stacks top on top of the main component, and if
    89→// u.Frame is set to true and the given frame argument too, it will
    90→// union the frames of the adjacent components with the configured
    91→// union charset. This method panics if top is nil.
    92→func (u *FrameUnion) UnionTopFrame(top tui.Component, height int, frame bool) {
    93→	if top == nil {
    94→		panic("invalid componen.Virtual")
    95→	}
    96→	u.top = append(u.top, &frameVirtual{
    97→		Virtual: Virtual[tui.Component]{C: top},
    98→		size:    height,
    99→		frame:   frame,
   100→	})
   101→	u.Resize(u.width, u.height)
   102→}
   103→
   104→// UnionBottom stacks bottom under of the main component. This
   105→// method panics if bottom is nil.
   106→func (u *FrameUnion) UnionBottom(bottom tui.Component, height int) {
   107→	u.UnionBottomFrame(bottom, height, true)
   108→}
   109→
   110→// UnionBottomFrame stacks bottom under of the main component, and if
   111→// u.Frame is set to true and the given frame argument too, it will
   112→// union the frames of the adjacent components with the configured
   113→// union charset. This method panics if bottom is nil.
   114→func (u *FrameUnion) UnionBottomFrame(bottom tui.Component, height int, frame bool) {
   115→	if bottom == nil {
   116→		panic("invalid componen.Virtual")
   117→	}
   118→	head := []*frameVirtual{{
   119→		Virtual: Virtual[tui.Component]{C: bottom},
   120→		size:    height,
   121→		frame:   frame,
   122→	}}
   123→	u.bottom = append(head, u.bottom...)
   124→	u.Resize(u.width, u.height)
   125→}
   126→
   127→// UnionLeft stacks left to the left of the main component. This
   128→// method panics if left is nil.
   129→func (u *FrameUnion) UnionLeft(left tui.Component, width int) {
   130→	u.UnionLeftFrame(left, width, true)
   131→}
   132→
   133→// UnionLeftFrame stacks left to the left of the main component, and if
   134→// u.Frame is set to true and the given frame argument too, it will
   135→// union the frames of the adjacent components with the configured
   136→// union charset. This method panics if left is nil.
   137→func (u *FrameUnion) UnionLeftFrame(left tui.Component, width int, frame bool) {
   138→	if left == nil {
   139→		panic("invalid componen.Virtual")
   140→	}
   141→	u.left = append(u.left, &frameVirtual{
   142→		Virtual: Virtual[tui.Component]{C: left},
   143→		size:    width,
   144→		frame:   frame,
   145→	})
   146→	u.Resize(u.width, u.height)
   147→}
   148→
   149→// UnionRight stacks right to the right of the main component. This
   150→// method panics if right is nil.
   151→func (u *FrameUnion) UnionRight(right tui.Component, width int) {
   152→	u.UnionRightFrame(right, width, true)
   153→}
   154→
   155→// UnionRightFrame stacks right to the right of the main component, and if
   156→// u.Frame is set to true and the given frame argument too, it will
   157→// union the frames of the adjacent components with the configured
   158→// union charset. This method panics if right is nil.
   159→func (u *FrameUnion) UnionRightFrame(right tui.Component, width int, frame bool) {
   160→	if right == nil {
   161→		panic("invalid componen.Virtual")
   162→	}
   163→	head := []*frameVirtual{{
   164→		Virtual: Virtual[tui.Component]{C: right},
   165→		frame:   frame,
   166→		size:    width,
   167→	}}
   168→	u.right = append(head, u.right...)
   169→	u.Resize(u.width, u.height)
   170→}
   171→
   172→// ComponentAt returns the component at pos or false if there's no component at pos.
   173→func (u *FrameUnion) ComponentAt(pos term.Coordinates) (Virtual[tui.Component], bool) {
   174→	frameVirtualMain := frameVirtual{Virtual: u.main}
   175→	main := [1]*frameVirtual{&frameVirtualMain}
   176→	c, ok := u.componentAt(main[:], pos)
   177→	if ok {
   178→		return c, true
   179→	}
   180→	c, ok = u.componentAt(u.top, pos)
   181→	if ok {
   182→		return c, true
   183→	}
   184→	c, ok = u.componentAt(u.bottom, pos)
   185→	if ok {
   186→		return c, true
   187→	}
   188→	c, ok = u.componentAt(u.left, pos)
   189→	if ok {
   190→		return c, true
   191→	}
   192→	return u.componentAt(u.right, pos)
   193→}
   194→
   195→// MainPosition returns the main component's offset from the top-left corner.
   196→func (u *FrameUnion) MainPosition() (offset term.Coordinates) {
   197→	return u.main.Position()
   198→}
   199→
   200→// MainWidth returns the main component's width.
   201→func (u *FrameUnion) MainWidth() int {
   202→	return u.main.Width()
   203→}
   204→
   205→// MainHeight returns the main component's height.
   206→func (u *FrameUnion) MainHeight() int {
   207→	return u.main.Height()
   208→}
   209→
   210→// Resize satisfies tui.Component
   211→func (u *FrameUnion) Resize(width, height int) {
   212→	u.height, u.width = height, width
   213→
   214→	mainHeight, topOffset := u.resizeTopBottom(width, height)
   215→	mainWidth, leftOffset := u.resizeLeftRight(width, mainHeight, topOffset)
   216→
   217→	u.main.Resize(mainWidth, mainHeight)
   218→	u.main.Move(term.Coordinates{Y: topOffset, X: leftOffset})
   219→}
   220→
   221→// Draw satisfies tui.Component
   222→func (u *FrameUnion) Draw(w term.Writer) {
   223→	for _, top := range u.top {
   224→		top.Draw(w)
   225→	}
   226→	for _, bottom := range u.bottom {
   227→		bottom.Draw(w)
   228→	}
   229→	for _, left := range u.left {
   230→		left.Draw(w)
   231→	}
   232→	for _, right := range u.right {
   233→		right.Draw(w)
   234→	}
   235→
   236→	u.main.Draw(w)
   237→
   238→	if u.main.Height() < 2 || u.main.Width() < 2 || !u.Frame {
   239→		return
   240→	}
   241→
   242→	u.drawUnionCells(w)
   243→}
   244→
   245→type frameVirtual struct {
   246→	size int
   247→	Virtual[tui.Component]
   248→	frame bool
   249→}
   250→
   251→func (u *FrameUnion) drawUnionCells(w term.Writer) {
   252→	var prevStamp bool
   253→	for i, left := range u.left {
   254→		if !left.frame || (i < len(u.left)-1 && !u.left[i+1].frame) {
   255→			prevStamp = false
   256→			continue
   257→		}
   258→		topCh := u.Top
   259→		bottomCh := u.Bottom
   260→		pos := left.Position()
   261→
   262→		if !prevStamp && i != 0 {
   263→			u.setHorizontalUnionFrameCells(w, topCh, bottomCh, left, u.main.Height(), pos.X, pos.Y)
   264→		}
   265→		prevStamp = true
   266→		u.setHorizontalUnionFrameCells(w, topCh, bottomCh, left, u.main.Height(), pos.X+left.Width()-1, pos.Y)
   267→	}
   268→
   269→	prevStamp = false
   270→	for i := len(u.right) - 1; i >= 0; i-- {
   271→		right := u.right[i]
   272→		if !right.frame || (i > 0 && !u.right[i-1].frame) {
   273→			prevStamp = false
   274→			continue
   275→		}
   276→		pos := right.Position()
   277→		topCh := u.Top
   278→		bottomCh := u.Bottom
   279→
   280→		if !prevStamp && i != len(u.right)-1 {
   281→			u.setHorizontalUnionFrameCells(w, topCh, bottomCh, right, u.main.Height(), pos.X+right.Width()-1, pos.Y)
   282→		}
   283→		prevStamp = true
   284→		u.setHorizontalUnionFrameCells(w, topCh, bottomCh, right, u.main.Height(), pos.X, pos.Y)
   285→	}
   286→
   287→	for i, top := range u.top {
   288→		if !top.frame || (i < len(u.top)-1 && !u.top[i+1].frame) {
   289→			continue
   290→		}
   291→		leftCh := u.Left
   292→		rightCh := u.Right
   293→		if i == len(u.top)-1 && len(u.left) != 0 && !u.left[0].frame {
   294→			leftCh = u.BottomLeft
   295→		}
   296→		if i == len(u.top)-1 && len(u.right) != 0 && !u.right[len(u.right)-1].frame {
   297→			rightCh = u.BottomRight
   298→		}
   299→		u.setVerticalUnionFrameCells(w, leftCh, rightCh, top, top.Position().Y+top.Height()-1)
   300→	}
   301→
   302→	for i, bottom := range u.bottom {
   303→		if !bottom.frame || (i > 0 && !u.bottom[i-1].frame) {
   304→			continue
   305→		}
   306→		leftCh := u.Left
   307→		rightCh := u.Right
   308→		if i == 0 && len(u.left) != 0 && !u.left[0].frame {
   309→			leftCh = u.TopLeft
   310→		}
   311→		if i == 0 && len(u.right) != 0 && !u.right[len(u.right)-1].frame {
   312→			rightCh = u.TopRight
   313→		}
   314→		u.setVerticalUnionFrameCells(w, leftCh, rightCh, bottom, bottom.Position().Y)
   315→	}
   316→}
   317→
   318→func (u *FrameUnion) setVerticalUnionFrameCells(
   319→	w term.Writer, left, right rune, v *frameVirtual, y int,
   320→) {
   321→	if v.Height() == 0 || v.Width() == 0 {
   322→		return
   323→	}
   324→	w.SetCell(term.Coordinates{Y: y},
   325→		term.Cell{Width: 1, Ch: left, Attributes: u.Attributes})
   326→	if u.width > 0 {
   327→		w.SetCell(term.Coordinates{X: u.width - 1, Y: y},
   328→			term.Cell{Width: 1, Ch: right, Attributes: u.Attributes})
   329→	}
   330→}
   331→
   332→func (u *FrameUnion) componentAt(
   333→	components []*frameVirtual, pos term.Coordinates,
   334→) (Virtual[tui.Component], bool) {
   335→	for _, t := range components {
   336→		tpos := t.Position()
   337→		twidth := t.Width()
   338→		theight := t.Height()
   339→		if pos.X >= tpos.X && pos.Y >= tpos.Y && pos.X < tpos.X+twidth && pos.Y < tpos.Y+theight {
   340→			return t.Virtual, true
   341→		}
   342→	}
   343→	return Virtual[tui.Component]{}, false
   344→}
   345→
   346→func (u *FrameUnion) setHorizontalUnionFrameCells(
   347→	w term.Writer, top, bottom rune, v *frameVirtual, height, x, y int,
   348→) {
   349→	if v.Height() == 0 || v.Width() == 0 {
   350→		return
   351→	}
   352→	w.SetCell(term.Coordinates{X: x, Y: y},
   353→		term.Cell{Width: 1, Ch: top, Attributes: u.Attributes})
   354→	if height > 0 {
   355→		w.SetCell(term.Coordinates{X: x, Y: y + height - 1},
   356→			term.Cell{Width: 1, Ch: bottom, Attributes: u.Attributes})
   357→	}
   358→}
   359→
   360→func (u *FrameUnion) resizeTopBottom(totalWidth, totalHeight int) (int, int) {
   361→	var topOffset int
   362→	var prevOverlap bool
   363→	for _, top := range u.top {
   364→		if u.Frame && top.frame && prevOverlap {
   365→			topOffset--
   366→		}
   367→		prevOverlap = top.frame
   368→		coords := term.Coordinates{Y: topOffset}
   369→		top.Move(coords)
   370→
   371→		height := top.size
   372→		if height > 0 {
   373→			topOffset += height
   374→			top.Resize(totalWidth, height)
   375→		} else {
   376→			top.Resize(0, 0)
   377→		}
   378→	}
   379→
   380→	if prevOverlap && u.Frame && len(u.top) != 0 {
   381→		topOffset--
   382→	}
   383→
   384→	prevOverlap = u.Frame
   385→	var bottomHeight int
   386→	for _, bottom := range u.bottom {
   387→		if u.Frame && bottom.frame && prevOverlap {
   388→			bottomHeight--
   389→		}
   390→		prevOverlap = bottom.frame
   391→		height := bottom.size
   392→		if height > 0 {
   393→			bottomHeight += height
   394→		}
   395→	}
   396→
   397→	// if there's too many union components for available height
   398→	// do not draw them.
   399→	mainHeight := totalHeight - topOffset - bottomHeight
   400→	if (u.Frame && mainHeight < 2) || mainHeight < 1 {
   401→		for _, top := range u.top {
   402→			top.Resize(0, 0)
   403→		}
   404→		for _, bottom := range u.bottom {
   405→			bottom.Resize(0, 0)
   406→		}
   407→		return totalHeight, 0
   408→	}
   409→
   410→	bottomOffset := totalHeight - bottomHeight
   411→	prevOverlap = u.Frame
   412→	for _, bottom := range u.bottom {
   413→		if u.Frame && bottom.frame && prevOverlap {
   414→			bottomOffset--
   415→		}
   416→		prevOverlap = bottom.frame
   417→		coords := term.Coordinates{Y: bottomOffset}
   418→		bottom.Move(coords)
   419→		height := bottom.size
   420→		if height > 0 {
   421→			bottom.Resize(totalWidth, height)
   422→			bottomOffset += height
   423→		} else {
   424→			bottom.Resize(0, 0)
   425→		}
   426→	}
   427→
   428→	return mainHeight, topOffset
   429→}
   430→
   431→func (u *FrameUnion) resizeLeftRight(totalWidth, totalHeight, topOffset int) (int, int) {
   432→	var leftOffset int
   433→	var prevOverlap bool
   434→	for _, left := range u.left {
   435→		if u.Frame && left.frame && prevOverlap {
   436→			leftOffset--
   437→		}
   438→		prevOverlap = left.frame
   439→		left.Move(term.Coordinates{X: leftOffset, Y: topOffset})
   440→
   441→		width := left.size
   442→		if width > 0 {
   443→			leftOffset += width
   444→			left.Resize(width, totalHeight)
   445→		} else {
   446→			left.Resize(0, 0)
   447→		}
   448→	}
   449→	if prevOverlap && u.Frame && len(u.left) != 0 {
   450→		leftOffset--
   451→	}
   452→
   453→	prevOverlap = u.Frame
   454→	var rightWidth int
   455→	for _, right := range u.right {
   456→		if u.Frame && right.frame && prevOverlap {
   457→			rightWidth--
   458→		}
   459→		prevOverlap = right.frame
   460→		width := right.size
   461→		if width > 0 {
   462→			rightWidth += width
   463→		}
   464→	}
   465→
   466→	mainWidth := totalWidth - leftOffset - rightWidth
   467→	if (u.Frame && mainWidth < 2) || mainWidth < 1 {
   468→		for _, left := range u.left {
   469→			left.Resize(0, 0)
   470→		}
   471→		for _, right := range u.right {
   472→			right.Resize(0, 0)
   473→		}
   474→		return totalWidth, 0
   475→	}
   476→
   477→	rightOffset := totalWidth - rightWidth
   478→	prevOverlap = u.Frame
   479→	for _, right := range u.right {
   480→		if u.Frame && right.frame && prevOverlap {
   481→			rightOffset--
   482→		}
   483→		prevOverlap = right.frame
   484→		right.Move(term.Coordinates{Y: topOffset, X: rightOffset})
   485→		width := right.size
   486→		if width > 0 {
   487→			right.Resize(width, totalHeight)
   488→			rightOffset += width
   489→		} else {
   490→			right.Resize(0, 0)
   491→		}
   492→	}
   493→
   494→	return mainWidth, leftOffset
   495→}
