package markdown

import (
	"github.com/unstablebuild/rune-go-sdk/component"
	"github.com/unstablebuild/rune-go-sdk/term"
	"github.com/unstablebuild/tcell/v3"
)

// Config defines the styling options for markdown rendering.
type Config struct {
	// Header styles (H1-H6)
	H1, H2, H3, H4, H5, H6 term.Attributes

	// Text styles
	Paragraph     term.Attributes
	Bold          term.Attributes
	Italic        term.Attributes
	Strikethrough term.Attributes

	// Code styles
	CodeBlock  term.Attributes
	InlineCode term.Attributes

	// Link styles
	Link    term.Attributes
	LinkURL term.Attributes

	// Blockquote styling
	Blockquote       term.Attributes
	BlockquoteBorder rune

	// List styling
	ListBullet        rune
	TaskListChecked   rune
	TaskListUnchecked rune

	// Table styling
	TableCharSet TableCharSet

	// Horizontal rule styling
	HorizontalRule     rune
	HorizontalRuleAttr term.Attributes

	// Spacing
	ParagraphSpacing int
}

// TableCharSet defines the characters used to draw table borders.
type TableCharSet struct {
	component.FrameCharSet
	HeaderSeparator rune
	ColumnSeparator rune
	CrossJoin       rune
	LeftJoin        rune
	RightJoin       rune
}

// DefaultTableCharSet returns the default table character set.
func DefaultTableCharSet() TableCharSet {
	return TableCharSet{
		FrameCharSet:    component.FrameCharSetDefault(),
		HeaderSeparator: '─',
		ColumnSeparator: '│',
		CrossJoin:       '┼',
		LeftJoin:        '├',
		RightJoin:       '┤',
	}
}

// DefaultConfig returns a Config with sensible defaults for terminal rendering.
func DefaultConfig() Config {
	magenta := term.Attributes{Fg: tcell.ColorPurple}
	magentaBold := term.Attributes{Fg: tcell.ColorPurple, Attrs: tcell.AttrBold}
	cyan := term.Attributes{Fg: tcell.ColorTeal}
	cyanUnderline := term.Attributes{Fg: tcell.ColorTeal, Attrs: tcell.AttrUnderline}
	yellow := term.Attributes{Fg: tcell.ColorYellow}
	gray := term.Attributes{Fg: tcell.ColorGray}
	white := term.Attributes{Fg: tcell.ColorWhite}
	whiteBold := term.Attributes{Fg: tcell.ColorWhite, Attrs: tcell.AttrBold}
	whiteItalic := term.Attributes{Fg: tcell.ColorWhite, Attrs: tcell.AttrItalic}
	dimWhite := term.Attributes{Fg: tcell.ColorDimGray}
	dimWhiteStrike := term.Attributes{
		Fg: tcell.ColorDimGray, Attrs: tcell.AttrStrikeThrough,
	}

	return Config{
		H1: magentaBold,
		H2: magentaBold,
		H3: magentaBold,
		H4: magenta,
		H5: magenta,
		H6: magenta,

		Paragraph:     white,
		Bold:          whiteBold,
		Italic:        whiteItalic,
		Strikethrough: dimWhiteStrike,

		CodeBlock:  yellow,
		InlineCode: yellow,

		Link:    cyanUnderline,
		LinkURL: cyan,

		Blockquote:       dimWhite,
		BlockquoteBorder: '│',

		ListBullet:        '•',
		TaskListChecked:   '☑',
		TaskListUnchecked: '☐',

		TableCharSet: DefaultTableCharSet(),

		HorizontalRule:     '─',
		HorizontalRuleAttr: gray,

		ParagraphSpacing: 1,
	}
}

