package markdown

import (
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	"github.com/unstablebuild/rune-go-sdk/term"
)

func TestComponentNew(t *testing.T) {
	md := New("# Hello")
	require.NotNil(t, md)
	assert.NotEmpty(t, md.blocks)
}

func TestComponentNewWithConfig(t *testing.T) {
	cfg := DefaultConfig()
	md := NewWithConfig("# Hello", cfg)
	require.NotNil(t, md)
	assert.NotEmpty(t, md.blocks)
}

func TestComponentResize(t *testing.T) {
	md := New("# Hello\n\nWorld")
	md.Resize(40, 10)
	assert.Equal(t, 40, md.width)
	assert.Equal(t, 10, md.height)
	assert.Greater(t, md.totalHeight, 0)
}

func TestComponentResizeThenDraw(t *testing.T) {
	md := New("Hi")
	w := term.NewStringWriter(10, 3)

	md.Resize(10, 3)
	md.Draw(w)

	expected := "Hi        \n          \n          "
	assert.Equal(t, expected, w.String())
}

func TestComponentDimensions(t *testing.T) {
	md := New("# Hello\n\nParagraph 1\n\nParagraph 2")
	md.Resize(80, 24)
	width, height := md.Dimensions()
	assert.Equal(t, 80, width)
	assert.Equal(t, md.totalHeight, height)
}

func TestComponentScrolling(t *testing.T) {
	md := New("# H1\n\n# H2\n\n# H3\n\n# H4\n\n# H5")
	md.Resize(20, 3)

	assert.Equal(t, 0, md.SeekOffset())
	assert.False(t, md.SeekUp())

	if md.MaxSeekOffset() > 0 {
		assert.True(t, md.SeekDown())
		assert.Equal(t, 1, md.SeekOffset())

		assert.True(t, md.SeekUp())
		assert.Equal(t, 0, md.SeekOffset())
	}
}

func TestComponentMaxSeekOffset(t *testing.T) {
	tests := []struct {
		name           string
		content        string
		width          int
		height         int
		expectedMaxOff int
	}{
		{
			name:           "content fits",
			content:        "Hi",
			width:          20,
			height:         10,
			expectedMaxOff: 0,
		},
		{
			name:           "content exceeds viewport",
			content:        "# H1\n\n# H2\n\n# H3\n\n# H4\n\n# H5\n\n# H6\n\n# H7",
			width:          20,
			height:         3,
			expectedMaxOff: 11,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			md := New(tt.content)
			md.Resize(tt.width, tt.height)
			assert.Equal(t, tt.expectedMaxOff, md.MaxSeekOffset())
		})
	}
}

func TestComponentDraw(t *testing.T) {
	tests := []struct {
		name     string
		content  string
		width    int
		height   int
		expected string
	}{
		{
			name:     "simple paragraph",
			content:  "Hi",
			width:    10,
			height:   3,
			expected: "Hi        \n          \n          ",
		},
		{
			name:     "header",
			content:  "# Title",
			width:    10,
			height:   3,
			expected: "Title     \n          \n          ",
		},
		{
			name:     "header and paragraph",
			content:  "# H1\n\nText",
			width:    10,
			height:   4,
			expected: "H1        \n          \nText      \n          ",
		},
		{
			name:     "horizontal rule",
			content:  "---",
			width:    5,
			height:   2,
			expected: "─────\n     ",
		},
		{
			name:     "unordered list",
			content:  "- A\n- B",
			width:    10,
			height:   4,
			expected: "• A       \n• B       \n          \n          ",
		},
		{
			name:     "code block",
			content:  "```\ncode\n```",
			width:    10,
			height:   3,
			expected: "code      \n          \n          ",
		},
		{
			name:     "blockquote",
			content:  "> quote",
			width:    10,
			height:   3,
			expected: "│ quote   \n          \n          ",
		},
		{
			name:    "table with full box",
			content: "| A | B |\n|---|---|\n| 1 | 2 |",
			width:   10,
			height:  7,
			expected: "┌────┬───┐\n" +
				"│A   │B  │\n" +
				"├────┼───┤\n" +
				"│1   │2  │\n" +
				"└────┴───┘\n" +
				"          \n" +
				"          ",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			md := New(tt.content)
			w := term.NewStringWriter(tt.width, tt.height)

			md.Resize(tt.width, tt.height)
			md.Draw(w)

			assert.Equal(t, tt.expected, w.String())
		})
	}
}

func TestComponentDrawWithScroll(t *testing.T) {
	md := New("# H1\n\n# H2\n\n# H3")
	w := term.NewStringWriter(10, 2)

	md.Resize(10, 2)
	md.Draw(w)
