func TestComponentMaxSeekOffset(t *testing.T) {
	tests := []struct {
		name           string
		content        string
		width          int
		height         int
		expectedMaxOff int
	}{
		{
			name:           "content fits",
			content:        "Hi",
			width:          20,
			height:         10,
			expectedMaxOff: 0,
		},
		{
			name:           "content exceeds viewport",
			content:        "# H1\n\n# H2\n\n# H3\n\n# H4\n\n# H5\n\n# H6\n\n# H7",
			width:          20,
			height:         3,
			expectedMaxOff: 11,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
