		},
		{
			name:     "horizontal rule",
			content:  "---",
			width:    5,
			height:   2,
			expected: "─────\n     ",
		},
		{
			name:     "unordered list",
			content:  "- A\n- B",
			width:    10,
			height:   4,
			expected: "• A       \n• B       \n          \n          ",
		},
		{
			name:     "code block",
			content:  "```\ncode\n```",
			width:    10,
			height:   3,
			expected: "code      \n          \n          ",
		},
		{
			name:     "blockquote",
			content:  "> quote",
			width:    10,
			height:   3,
			expected: "│ quote   \n          \n          ",
		},
