    15→package term
    16→
    17→import (
    18→	"bytes"
    19→	"context"
    20→	"fmt"
    21→)
    22→
    23→var _ Writer = (*StringWriter)(nil)
    24→
    25→// StringWriter satisfies Writer by rendering the cells into a plain string.
    26→type StringWriter struct {
    27→	cellbuf       []Cell
    28→	buffer        bytes.Buffer
    29→	width, height int
    30→	CursorCh      rune
    31→	SetContext    context.Context
    32→	BackgroundCh  rune
    33→	ForegroundCh  rune
    34→}
    35→
    36→// NewStringWriter allocates storage for a new StringWriter and
    37→// initializes it.
    38→func NewStringWriter(width, height int) (t *StringWriter) {
    39→	t = new(StringWriter)
    40→	t.Init(width, height)
    41→	return
    42→}
    43→
    44→// Init initializes this StringWriter with the given height and width.
    45→func (w *StringWriter) Init(width, height int) {
    46→	w.Resize(width, height)
    47→	w.CursorCh = '▐'
    48→	w.SetContext = context.Background()
    49→}
    50→
    51→// Context returns context.Background
    52→func (w *StringWriter) Context() context.Context {
    53→	return w.SetContext
    54→}
    55→
    56→// Resize satisfies Writer.
    57→func (w *StringWriter) Resize(width, height int) {
    58→	w.width, w.height = width, height
    59→	w.cellbuf = make([]Cell, width*height)
    60→}
    61→
    62→// Reset resets this writer.
    63→func (w *StringWriter) Reset() {
    64→	w.Init(w.width, w.height)
    65→	w.buffer.Reset()
    66→}
    67→
    68→func outOfBounds(height, width int, pos Coordinates) bool {
    69→	return pos.X >= width || pos.Y >= height || pos.X < 0 || pos.Y < 0
    70→}
    71→
    72→// SetCell satisfies Writer.
    73→func (w *StringWriter) SetCell(pos Coordinates, cell Cell) {
    74→	if outOfBounds(w.height, w.width, pos) {
    75→		panic(fmt.Sprintf("SetCell(x=%d;y=%d): out of bounds: width=%d;height=%d",
    76→			pos.X, pos.Y, w.width, w.height))
    77→	}
    78→	idx := pos.Y*w.width + pos.X
    79→	w.cellbuf[idx] = cell
    80→}
    81→
    82→// UnionAttributes satisfies Writer.
    83→func (w *StringWriter) UnionAttributes(pos Coordinates, attr Attributes) {
    84→	if outOfBounds(w.height, w.width, pos) {
    85→		panic(fmt.Sprintf("SetCell(x=%d;y=%d): out of bounds: width=%d;height=%d",
    86→			pos.X, pos.Y, w.width, w.height))
    87→	}
    88→	idx := pos.Y*w.width + pos.X
    89→	w.cellbuf[idx].Attributes = AttributesUnion(w.cellbuf[idx].Attributes, attr)
    90→}
    91→
    92→// Flush flushes the contents of this writer into the underlying cell buffer.
    93→func (w *StringWriter) Flush() (err error) {
    94→	for i, c := range w.cellbuf {
    95→		if i != 0 && i%w.width == 0 {
    96→			w.buffer.WriteRune('\n')
    97→		}
    98→		ch := c.Ch
    99→		switch ch {
   100→		case '\t', '\n', 0:
   101→			ch = ' '
   102→		}
   103→		if w.BackgroundCh != 0 && c.Bg != 0 {
   104→			ch = w.BackgroundCh
   105→		}
   106→		if w.ForegroundCh != 0 && c.Fg != 0 {
   107→			ch = w.ForegroundCh
   108→		}
   109→		w.buffer.WriteRune(ch)
   110→	}
   111→	return
   112→}
   113→
   114→// Cells returns the internal cell slice.
   115→func (w *StringWriter) Cells() []Cell {
   116→	return w.cellbuf
   117→}
   118→
   119→// Clear satisfies Writer. Note that attr are ignored as they
   120→// can't be represented in a string.
   121→func (w *StringWriter) Clear(attr Attributes) (err error) {
   122→	w.cellbuf = make([]Cell, w.width*w.height)
   123→	w.buffer.Reset()
   124→	return
   125→}
   126→
   127→// String returns the string representation of the contents of this Writer.
   128→func (w *StringWriter) String() string {
   129→	return w.buffer.String()
   130→}
   131→
   132→// SetCursor satisfies Writer by substituting the rune
   133→// at pos for a pre-defined cursor-like rune.
   134→func (w *StringWriter) SetCursor(pos Coordinates) {
   135→	i := pos.X + pos.Y*w.width
   136→	if i < len(w.cellbuf) {
   137→		w.cellbuf[i].Ch = w.CursorCh
   138→	}
   139→}
