   106→func (w *blockWalker) walkInline(n ast.Node, style InlineStyle, run *TextRun) {
   107→	for child := n.FirstChild(); child != nil; child = child.NextSibling() {
   108→		switch node := child.(type) {
   109→		case *ast.Text:
   110→			text := string(node.Segment.Value(w.source))
   111→			if node.SoftLineBreak() || node.HardLineBreak() {
   112→				text += " "
   113→			}
   114→			*run = append(*run, Span{Text: text, Style: style})
   115→
   116→		case *ast.String:
   117→			*run = append(*run, Span{Text: string(node.Value), Style: style})
   118→
   119→		case *ast.Emphasis:
   120→			newStyle := style
   121→			if node.Level == 1 {
   122→				newStyle |= StyleItalic
   123→			} else {
   124→				newStyle |= StyleBold
   125→			}
   126→			w.walkInline(node, newStyle, run)
   127→
   128→		case *ast.CodeSpan:
   129→			*run = append(*run, Span{
   130→				Text:  w.extractCodeSpanText(node),
   131→				Style: style | StyleCode,
   132→			})
   133→
   134→		case *ast.Link:
   135→			linkRun := TextRun{}
   136→			w.walkInline(node, style|StyleLink, &linkRun)
   137→			for i := range linkRun {
   138→				linkRun[i].URL = string(node.Destination)
   139→			}
   140→			*run = append(*run, linkRun...)
   141→
   142→		case *ast.AutoLink:
   143→			url := string(node.URL(w.source))
   144→			*run = append(*run, Span{
   145→				Text:  url,
   146→				Style: style | StyleLink,
   147→				URL:   url,
   148→			})
   149→
   150→		case *extast.Strikethrough:
   151→			w.walkInline(node, style|StyleStrikethrough, run)
   152→
   153→		default:
   154→			w.walkInline(child, style, run)
   155→		}
   156→	}
   157→}
