package markdown

import (
	"github.com/unstablebuild/rune-go-sdk/component"
	"github.com/unstablebuild/rune-go-sdk/term"
)

// Component renders markdown content in a terminal.
// It implements component.ScrollableFloating.
type Component struct {
	blocks []Block
	cfg    Config

	width, height int
	offset        int
	totalHeight   int
	heightCache   []int
	cacheWidth    int
}

var _ component.ScrollableFloating = (*Component)(nil)

// New creates a new markdown component with the given content
// using default styling.
func New(content string) *Component {
	return NewWithConfig(content, DefaultConfig())
}

// NewWithConfig creates a new markdown component with the given content
// and custom configuration.
func NewWithConfig(content string, cfg Config) *Component {
	blocks, _ := Parse(content)
	return NewWithBlocks(blocks, cfg)
}

// NewWithBlocks creates a new markdown component with the given content
// and custom configuration.
func NewWithBlocks(blocks []Block, cfg Config) *Component {
	return &Component{
		blocks: blocks,
		cfg:    cfg,
	}
}

// Resize updates the viewport dimensions and recalculates block heights
// if the width has changed.
func (c *Component) Resize(width, height int) {
	c.width, c.height = width, height
	if c.heightCache == nil || c.cacheWidth != width {
		c.recalculateHeights()
	}
	if max := c.MaxSeekOffset(); c.offset > max {
		c.offset = max
	}
}

// Draw renders the visible portion of the markdown content.
func (c *Component) Draw(w term.Writer) {
	if c.width <= 0 || c.height <= 0 {
		return
	}
	w = term.BoundsCheckWriter(c.width, c.height, w)
	y := -c.offset
	for i, block := range c.blocks {
		blockHeight := c.heightCache[i]
		if y+blockHeight <= 0 {
			y += blockHeight
			continue
		}
		if y >= c.height {
			break
		}
		vw := &component.VirtualWriter{
			Writer: w,
			Offset: term.Coordinates{X: 0, Y: y},
			Width:  c.width,
			Height: blockHeight,
		}
		block.Render(vw, 0, c.width, &c.cfg)
		y += blockHeight
	}
}

// SeekUp scrolls the content up by one row.
// Returns true if scrolling occurred.
func (c *Component) SeekUp() bool {
	if c.offset > 0 {
		c.offset--
		return true
	}
	return false
}

// SeekDown scrolls the content down by one row.
// Returns true if scrolling occurred.
func (c *Component) SeekDown() bool {
	if c.offset < c.MaxSeekOffset() {
		c.offset++
		return true
	}
	return false
}

// SeekOffset returns the current scroll offset.
func (c *Component) SeekOffset() int {
	return c.offset
}

// MaxSeekOffset returns the maximum scroll offset.
func (c *Component) MaxSeekOffset() int {
	if c.totalHeight <= c.height {
		return 0
	}
	return c.totalHeight - c.height
}

// Dimensions returns the preferred width and total content height.
func (c *Component) Dimensions() (width, height int) {
	return 80, c.totalHeight
}

func (c *Component) recalculateHeights() {
	c.heightCache = make([]int, len(c.blocks))
	c.totalHeight = 0
	for i, block := range c.blocks {
		h := block.Height(c.width)
		c.heightCache[i] = h
		c.totalHeight += h
	}
	c.cacheWidth = c.width
}

