package markdown

import (
	"github.com/unstablebuild/rune-go-sdk/term"
)

// ParagraphBlock represents a markdown paragraph with inline formatting.
type ParagraphBlock struct {
	Content TextRun
}

var _ Block = (*ParagraphBlock)(nil)

// Height returns the number of rows this paragraph will occupy.
func (p *ParagraphBlock) Height(width int) int {
	if width <= 0 {
		return 0
	}
	lines := countWrappedLines(p.Content, width)
	return lines + 1
}

// Render draws the paragraph to the writer.
func (p *ParagraphBlock) Render(w term.Writer, y, width int, cfg *Config) int {
	if width <= 0 {
		return 0
	}

	lines := wrapTextRun(p.Content, width)
	for i, line := range lines {
		x := 0
		for _, span := range line {
			attr := resolveStyle(span.Style, cfg)
			for _, r := range span.Text {
				if x >= width {
					break
				}
				w.SetCell(term.Coordinates{X: x, Y: y + i}, term.Cell{
					Ch:         r,
					Width:      1,
					Attributes: attr,
				})
				x++
			}
		}
	}

	return len(lines) + 1
}

