package markdown

import (
	"github.com/unstablebuild/rune-go-sdk/term"
)

// HeaderBlock represents a markdown header (H1-H6).
type HeaderBlock struct {
	Level   int
	Content TextRun
}

var _ Block = (*HeaderBlock)(nil)

// Height returns the number of rows this header will occupy.
// Headers get spacing after them.
func (h *HeaderBlock) Height(width int) int {
	if width <= 0 {
		return 0
	}
	lines := countWrappedLines(h.Content, width)
	return lines + 1
}

// Render draws the header to the writer.
func (h *HeaderBlock) Render(w term.Writer, y, width int, cfg *Config) int {
	if width <= 0 {
		return 0
	}

	attr := h.getAttr(cfg)
	lines := wrapTextRun(h.Content, width)

	for i, line := range lines {
		x := 0
		for _, span := range line {
			for _, r := range span.Text {
				if x >= width {
					break
				}
				w.SetCell(term.Coordinates{X: x, Y: y + i}, term.Cell{
					Ch:         r,
					Width:      1,
					Attributes: attr,
				})
				x++
			}
		}
	}

	return len(lines) + 1
}

func (h *HeaderBlock) getAttr(cfg *Config) term.Attributes {
	switch h.Level {
	case 1:
		return cfg.H1
	case 2:
		return cfg.H2
	case 3:
		return cfg.H3
	case 4:
		return cfg.H4
	case 5:
		return cfg.H5
	default:
		return cfg.H6
	}
}

