package markdown

import (
	"strings"

	"github.com/unstablebuild/rune-go-sdk/term"
)

// CodeBlock represents a fenced code block.
type CodeBlock struct {
	Language string
	Code     string
}

var _ Block = (*CodeBlock)(nil)

// Height returns the number of rows this code block will occupy.
func (c *CodeBlock) Height(width int) int {
	if width <= 0 {
		return 0
	}
	lines := strings.Split(c.Code, "\n")
	if len(lines) > 0 && lines[len(lines)-1] == "" {
		lines = lines[:len(lines)-1]
	}
	return len(lines) + 1
}

// Render draws the code block to the writer.
func (c *CodeBlock) Render(w term.Writer, y, width int, cfg *Config) int {
	if width <= 0 {
		return 0
	}

	lines := strings.Split(c.Code, "\n")
	if len(lines) > 0 && lines[len(lines)-1] == "" {
		lines = lines[:len(lines)-1]
	}

	for lineIdx, line := range lines {
		x := 0
		for _, r := range line {
			if x >= width {
				break
			}
			w.SetCell(term.Coordinates{X: x, Y: y + lineIdx}, term.Cell{
				Ch:         r,
				Width:      1,
				Attributes: cfg.CodeBlock,
			})
			x++
		}
	}

	return len(lines) + 1
}

