package markdown

import (
	"github.com/unstablebuild/rune-go-sdk/term"
)

const blockquoteIndent = 2

// BlockquoteBlock represents a markdown blockquote.
type BlockquoteBlock struct {
	Content []TextRun
	Nested  *BlockquoteBlock
}

var _ Block = (*BlockquoteBlock)(nil)

// Height returns the number of rows this blockquote will occupy.
func (b *BlockquoteBlock) Height(width int) int {
	return b.heightAtIndent(width, 0)
}

func (b *BlockquoteBlock) heightAtIndent(width, indent int) int {
	if width <= indent+blockquoteIndent {
		return 0
	}

	height := 0
	effectiveWidth := width - indent - blockquoteIndent

	for _, content := range b.Content {
		lines := countWrappedLines(content, effectiveWidth)
		height += lines
	}

	if b.Nested != nil {
		height += b.Nested.heightAtIndent(width, indent+blockquoteIndent)
	}

	return height + 1
}

// Render draws the blockquote to the writer.
func (b *BlockquoteBlock) Render(w term.Writer, y, width int, cfg *Config) int {
	return b.renderAtIndent(w, y, width, 0, cfg)
}

func (b *BlockquoteBlock) renderAtIndent(
	w term.Writer, y, width, indent int, cfg *Config,
) int {
	if width <= indent+blockquoteIndent {
		return 0
	}

	startY := y
	effectiveWidth := width - indent - blockquoteIndent

	for _, content := range b.Content {
		lines := wrapTextRun(content, effectiveWidth)
		for lineIdx, line := range lines {
			w.SetCell(term.Coordinates{X: indent, Y: y + lineIdx}, term.Cell{
				Ch:         cfg.BlockquoteBorder,
				Width:      1,
				Attributes: cfg.Blockquote,
			})

			x := indent + blockquoteIndent
			for _, span := range line {
				attr := resolveStyle(span.Style, cfg)
				attr = term.AttributesUnion(attr, cfg.Blockquote)
				for _, r := range span.Text {
					if x >= width {
						break
					}
					w.SetCell(term.Coordinates{X: x, Y: y + lineIdx}, term.Cell{
						Ch:         r,
						Width:      1,
						Attributes: attr,
					})
					x++
				}
			}
		}
		y += len(lines)
		if len(lines) == 0 {
			w.SetCell(term.Coordinates{X: indent, Y: y}, term.Cell{
				Ch:         cfg.BlockquoteBorder,
				Width:      1,
				Attributes: cfg.Blockquote,
			})
			y++
		}
	}

	if b.Nested != nil {
		nestedHeight := b.Nested.renderAtIndent(w, y, width, indent+blockquoteIndent, cfg)
		for i := 0; i < nestedHeight-1; i++ {
			w.SetCell(term.Coordinates{X: indent, Y: y + i}, term.Cell{
				Ch:         cfg.BlockquoteBorder,
				Width:      1,
				Attributes: cfg.Blockquote,
			})
		}
		y += nestedHeight
	}

	return y - startY + 1
}

