package markdown

import (
	"github.com/unstablebuild/rune-go-sdk/term"
)

// HorizontalRuleBlock represents a markdown horizontal rule (thematic break).
type HorizontalRuleBlock struct{}

var _ Block = (*HorizontalRuleBlock)(nil)

// Height returns the number of rows this horizontal rule will occupy.
// A horizontal rule takes 1 line plus spacing.
func (h *HorizontalRuleBlock) Height(width int) int {
	if width <= 0 {
		return 0
	}
	return 2
}

// Render draws the horizontal rule to the writer.
func (h *HorizontalRuleBlock) Render(w term.Writer, y, width int, cfg *Config) int {
	if width <= 0 {
		return 0
	}

	ch := cfg.HorizontalRule
	attr := cfg.HorizontalRuleAttr

	for x := 0; x < width; x++ {
		w.SetCell(term.Coordinates{X: x, Y: y}, term.Cell{
			Ch:         ch,
			Width:      1,
			Attributes: attr,
		})
	}

	return 2
}

