// block represents a parsed markdown block element that can be resized and drawn.
// It extends tui.Component with Dimensions for ideal size calculation.
type block interface {
	// Resize updates the block's viewport dimensions.
	Resize(width, height int)
	// Draw renders this block to the writer.
	Draw(w term.Writer)
	// Dimensions returns the ideal width and height (without wrapping/clipping).
	Dimensions() (width, height int)
	// height returns the current height after Resize was called.
	height() int
}

// inlineStyle represents text formatting flags that can be combined.
type inlineStyle uint8

const (
	styleNone          inlineStyle = 0
	styleBold          inlineStyle = 1 << iota
	styleItalic        inlineStyle = 1 << iota
	styleCode          inlineStyle = 1 << iota
	styleStrikethrough inlineStyle = 1 << iota
	styleLink          inlineStyle = 1 << iota
)

// span represents a segment of text with uniform styling.
type span struct {
	text  string
	style inlineStyle
	url   string // populated when style includes styleLink
}

// textRun is a sequence of spans that form inline content.
type textRun []span

// String returns the plain text content of the textRun.
func (tr textRun) String() string {
	var s string
	for _, sp := range tr {
		s += sp.text
	}
	return s
}

// Len returns the total character count of all spans.
func (tr textRun) Len() int {
	var n int
	for _, sp := range tr {
		n += len(sp.text)
	}
	return n
}

// resolveStyle converts an inlineStyle to term.Attributes using the config.
func resolveStyle(style inlineStyle, cfg *Config) term.Attributes {
	attr := cfg.Paragraph
	if style&styleBold != 0 {
		attr = cfg.Bold
	}
	if style&styleItalic != 0 {
		attr = cfg.Italic
	}
	if style&styleCode != 0 {
		attr = cfg.InlineCode
	}
	if style&styleStrikethrough != 0 {
		attr = cfg.Strikethrough
	}
	if style&styleLink != 0 {
		attr = cfg.Link
	}
	return attr
}

