		for _, sp := range line {
			attr := resolveStyle(sp.style, p.cfg)
			for _, r := range sp.text {
				if x >= p.w {
					break
				}
				w.SetCell(term.Coordinates{X: x, Y: i}, term.Cell{
					Ch:         r,
					Width:      1,
					Attributes: attr,
				})
				x++
			}
		}
	}
}

