	switch h.Level {
	case 1:
		return cfg.H1
	case 2:
		return cfg.H2
	case 3:
		return cfg.H3
	case 4:
		return cfg.H4
	case 5:
		return cfg.H5
	default:
		return cfg.H6
	}
}

