package markdown

import (
	"fmt"

	"github.com/unstablebuild/rune-go-sdk/term"
)

const listIndent = 2

// listItem represents a single item in a list.
type listItem struct {
	content textRun
	isTask  bool
	checked bool
	nested  *listBlock
}

// listBlock represents a markdown list (ordered or unordered).
type listBlock struct {
	ordered      bool
	start        int
	items        []listItem
	cfg          *Config
	w, h         int
	cachedHeight int
}

var _ block = (*listBlock)(nil)

func newListBlock(ordered bool, start int, items []listItem, cfg *Config) *listBlock {
	return &listBlock{ordered: ordered, start: start, items: items, cfg: cfg}
}

// Resize updates the block's viewport dimensions.
func (l *listBlock) Resize(width, height int) {
	l.w, l.h = width, height
	l.cachedHeight = l.heightAtIndent(width, 0)
}

func (l *listBlock) heightAtIndent(width, indent int) int {
	if width <= indent+listIndent {
		return 0
	}

	h := 0
	effectiveWidth := width - indent - listIndent

	for _, item := range l.items {
		lines := countWrappedLines(item.content, effectiveWidth)
		h += lines

		if item.nested != nil {
			h += item.nested.heightAtIndent(width, indent+listIndent)
		}
	}

	return h + 1
}

// Draw renders the list to the writer.
func (l *listBlock) Draw(w term.Writer) {
	l.drawAtIndent(w, 0, 0)
}

func (l *listBlock) drawAtIndent(w term.Writer, y, indent int) int {
	if l.w <= indent+listIndent {
		return 0
	}

	startY := y
	effectiveWidth := l.w - indent - listIndent

	for i, item := range l.items {
		bullet := l.getBullet(i, item)

		for j, r := range bullet {
			w.SetCell(term.Coordinates{X: indent + j, Y: y}, term.Cell{
				Ch:         r,
				Width:      1,
				Attributes: l.cfg.Paragraph,
			})
		}

		lines := wrapTextRun(item.content, effectiveWidth)
		for lineIdx, line := range lines {
			x := indent + listIndent
			for _, sp := range line {
				attr := resolveStyle(sp.style, l.cfg)
				for _, r := range sp.text {
					if x >= l.w {
						break
					}
					w.SetCell(term.Coordinates{X: x, Y: y + lineIdx}, term.Cell{
						Ch:         r,
						Width:      1,
						Attributes: attr,
					})
					x++
				}
			}
		}
		y += len(lines)
		if len(lines) == 0 {
			y++
		}

		if item.nested != nil {
			y += item.nested.drawAtIndent(w, y, indent+listIndent)
		}
	}

	return y - startY + 1
}

// Dimensions returns the ideal width and height (without wrapping).
func (l *listBlock) Dimensions() (width, height int) {
	return l.dimensionsAtIndent(0)
}

func (l *listBlock) dimensionsAtIndent(indent int) (width, height int) {
	maxWidth := 0
	totalHeight := 0

	for _, item := range l.items {
		itemWidth := indent + listIndent + item.content.Len()
		if itemWidth > maxWidth {
			maxWidth = itemWidth
		}
		totalHeight++ // one line per item

		if item.nested != nil {
			nestedW, nestedH := item.nested.dimensionsAtIndent(indent + listIndent)
			if nestedW > maxWidth {
				maxWidth = nestedW
			}
			totalHeight += nestedH - 1 // subtract spacing from nested
		}
	}

	return maxWidth, totalHeight + 1 // items + spacing
}

// height returns the current height after Resize.
func (l *listBlock) height() int {
	return l.cachedHeight
}

func (l *listBlock) getBullet(index int, item listItem) string {
	if item.isTask {
		if item.checked {
			return string(l.cfg.TaskListChecked) + " "
		}
		return string(l.cfg.TaskListUnchecked) + " "
	}

	if l.ordered {
		return fmt.Sprintf("%d.", l.start+index)
	}

	return string(l.cfg.ListBullet) + " "
}

