package markdown

import (
	"github.com/unstablebuild/rune-go-sdk/term"
)

// tableAlignment represents the alignment of a table column.
type tableAlignment int

const (
	alignLeft tableAlignment = iota
	alignCenter
	alignRight
)

// tableBlock represents a markdown table.
type tableBlock struct {
	header       []textRun
	rows         [][]textRun
	alignments   []tableAlignment
	cfg          *Config
	w, h         int
	cachedHeight int
}

var _ block = (*tableBlock)(nil)

func newTableBlock(header []textRun, rows [][]textRun, alignments []tableAlignment, cfg *Config) *tableBlock {
	return &tableBlock{header: header, rows: rows, alignments: alignments, cfg: cfg}
}

// Resize updates the block's viewport dimensions.
func (t *tableBlock) Resize(width, height int) {
	t.w, t.h = width, height
	if width <= 0 || len(t.header) == 0 {
		t.cachedHeight = 0
		return
	}
	// top border + header + separator + rows + bottom border + spacing
	t.cachedHeight = 1 + 1 + 1 + len(t.rows) + 1 + 1
}

// Draw renders the table to the writer.
func (t *tableBlock) Draw(w term.Writer) {
	if t.w <= 0 || len(t.header) == 0 {
		return
	}

	numCols := len(t.header)
	colWidths := t.calculateColumnWidths(t.w, numCols)
	cs := t.cfg.TableCharSet

	y := 0
	y = t.renderTopBorder(w, y, colWidths, cs)
	y = t.renderHeaderRow(w, y, colWidths, cs)
	y = t.renderSeparator(w, y, colWidths, cs)
	for _, row := range t.rows {
		y = t.renderDataRow(w, y, row, colWidths, cs)
	}
	t.renderBottomBorder(w, y, colWidths, cs)
}

// Dimensions returns the ideal width and height (without truncation).
func (t *tableBlock) Dimensions() (width, height int) {
	if len(t.header) == 0 {
		return 0, 0
	}

	// Calculate width needed for each column (max of header and all rows)
	numCols := len(t.header)
	colWidths := make([]int, numCols)

	for i, h := range t.header {
		if h.Len() > colWidths[i] {
			colWidths[i] = h.Len()
		}
	}
	for _, row := range t.rows {
		for i, cell := range row {
			if i < numCols && cell.Len() > colWidths[i] {
				colWidths[i] = cell.Len()
			}
		}
	}

	// Total width: borders + separators + column content
	totalWidth := 1 // left border
	for _, w := range colWidths {
		totalWidth += w + 1 // column + separator
	}

	// Height: top + header + separator + rows + bottom + spacing
	totalHeight := 1 + 1 + 1 + len(t.rows) + 1 + 1

	return totalWidth, totalHeight
}

// height returns the current height after Resize.
func (t *tableBlock) height() int {
	return t.cachedHeight
}

func (t *tableBlock) calculateColumnWidths(totalWidth, numCols int) []int {
	if numCols == 0 {
		return nil
	}
	availableWidth := totalWidth - (numCols + 1)
	baseWidth := availableWidth / numCols
	remainder := availableWidth % numCols

	widths := make([]int, numCols)
	for i := range widths {
		widths[i] = baseWidth
		if i < remainder {
			widths[i]++
		}
		if widths[i] < 1 {
			widths[i] = 1
		}
	}
	return widths
}

func (t *tableBlock) renderTopBorder(
	w term.Writer, y int, colWidths []int, cs TableCharSet,
) int {
	x := 0
	w.SetCell(term.Coordinates{X: x, Y: y}, term.Cell{
		Ch:         cs.TopLeft,
		Width:      1,
		Attributes: t.cfg.Paragraph,
	})
	x++

	for i, colWidth := range colWidths {
		for j := 0; j < colWidth; j++ {
			w.SetCell(term.Coordinates{X: x + j, Y: y}, term.Cell{
				Ch:         cs.HorizontalTop,
				Width:      1,
				Attributes: t.cfg.Paragraph,
			})
		}
		x += colWidth

		ch := cs.TopJoin
		if i == len(colWidths)-1 {
			ch = cs.TopRight
		}
		w.SetCell(term.Coordinates{X: x, Y: y}, term.Cell{
			Ch:         ch,
			Width:      1,
			Attributes: t.cfg.Paragraph,
		})
		x++
	}
	return y + 1
}

func (t *tableBlock) renderHeaderRow(
	w term.Writer, y int, colWidths []int, cs TableCharSet,
) int {
	x := 0
	w.SetCell(term.Coordinates{X: x, Y: y}, term.Cell{
		Ch:         cs.ColumnSeparator,
		Width:      1,
		Attributes: t.cfg.Paragraph,
	})
	x++

	for i, cell := range t.header {
		if i >= len(colWidths) {
			break
		}
		colWidth := colWidths[i]
		t.renderCell(w, x, y, colWidth, cell, t.getAlignment(i), true)
		x += colWidth

		w.SetCell(term.Coordinates{X: x, Y: y}, term.Cell{
			Ch:         cs.ColumnSeparator,
			Width:      1,
			Attributes: t.cfg.Paragraph,
		})
		x++
	}
	return y + 1
}

func (t *tableBlock) renderSeparator(
	w term.Writer, y int, colWidths []int, cs TableCharSet,
) int {
	x := 0

	w.SetCell(term.Coordinates{X: x, Y: y}, term.Cell{
		Ch:         cs.Left,
		Width:      1,
		Attributes: t.cfg.Paragraph,
	})
	x++

	for i, colWidth := range colWidths {
		for j := 0; j < colWidth; j++ {
			w.SetCell(term.Coordinates{X: x + j, Y: y}, term.Cell{
				Ch:         cs.HeaderSeparator,
				Width:      1,
				Attributes: t.cfg.Paragraph,
			})
		}
		x += colWidth

		ch := cs.CrossJoin
		if i == len(colWidths)-1 {
			ch = cs.Right
		}
		w.SetCell(term.Coordinates{X: x, Y: y}, term.Cell{
			Ch:         ch,
			Width:      1,
			Attributes: t.cfg.Paragraph,
		})
		x++
	}
	return y + 1
}

func (t *tableBlock) renderBottomBorder(
	w term.Writer, y int, colWidths []int, cs TableCharSet,
) int {
	x := 0
	w.SetCell(term.Coordinates{X: x, Y: y}, term.Cell{
		Ch:         cs.BottomLeft,
		Width:      1,
		Attributes: t.cfg.Paragraph,
	})
	x++

	for i, colWidth := range colWidths {
		for j := 0; j < colWidth; j++ {
			w.SetCell(term.Coordinates{X: x + j, Y: y}, term.Cell{
				Ch:         cs.HorizontalBottom,
				Width:      1,
				Attributes: t.cfg.Paragraph,
			})
		}
		x += colWidth

		ch := cs.BottomJoin
		if i == len(colWidths)-1 {
			ch = cs.BottomRight
		}
		w.SetCell(term.Coordinates{X: x, Y: y}, term.Cell{
			Ch:         ch,
			Width:      1,
			Attributes: t.cfg.Paragraph,
		})
		x++
	}
	return y + 1
}

func (t *tableBlock) renderDataRow(
	w term.Writer, y int, row []textRun, colWidths []int, cs TableCharSet,
) int {
	x := 0
	w.SetCell(term.Coordinates{X: x, Y: y}, term.Cell{
		Ch:         cs.ColumnSeparator,
		Width:      1,
		Attributes: t.cfg.Paragraph,
	})
	x++

	for i := 0; i < len(colWidths); i++ {
		colWidth := colWidths[i]
		var cell textRun
		if i < len(row) {
			cell = row[i]
		}
		t.renderCell(w, x, y, colWidth, cell, t.getAlignment(i), false)
		x += colWidth

		w.SetCell(term.Coordinates{X: x, Y: y}, term.Cell{
			Ch:         cs.ColumnSeparator,
			Width:      1,
			Attributes: t.cfg.Paragraph,
		})
		x++
	}
	return y + 1
}

func (t *tableBlock) renderCell(
	w term.Writer, x, y, width int, content textRun,
	align tableAlignment, isHeader bool,
) {
	text := content.String()
	textLen := len(text)
	if textLen > width {
		text = text[:width]
		textLen = width
	}

	var padding int
	switch align {
	case alignCenter:
		padding = (width - textLen) / 2
	case alignRight:
		padding = width - textLen
	}

	attr := t.cfg.Paragraph
	if isHeader {
		attr = t.cfg.Bold
	}

	spIdx := 0
	runeIdx := 0
	for i, r := range text {
		cellX := x + padding + i
		cellAttr := attr
		if spIdx < len(content) {
			sp := content[spIdx]
			if !isHeader {
				cellAttr = resolveStyle(sp.style, t.cfg)
			}
			runeIdx++
			if runeIdx >= len(sp.text) {
				spIdx++
				runeIdx = 0
			}
		}
		w.SetCell(term.Coordinates{X: cellX, Y: y}, term.Cell{
			Ch:         r,
			Width:      1,
			Attributes: cellAttr,
		})
	}
}

func (t *tableBlock) getAlignment(col int) tableAlignment {
	if col < len(t.alignments) {
		return t.alignments[col]
	}
	return alignLeft
}

