	y = t.renderHeaderRow(w, y, colWidths, cs, cfg)
	y = t.renderSeparator(w, y, colWidths, cs, cfg)
	for _, row := range t.Rows {
		y = t.renderDataRow(w, y, row, colWidths, cs, cfg)
	}
	t.renderBottomBorder(w, y, colWidths, cs, cfg)

	return t.Height(width)
}

