package markdown

import (
	"strings"
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	"github.com/unstablebuild/rune-go-sdk/term"
)

func TestHeaderBlockHeight(t *testing.T) {
	tests := []struct {
		name     string
		block    *HeaderBlock
		width    int
		expected int
	}{
		{
			name:     "simple header",
			block:    &HeaderBlock{Level: 1, Content: TextRun{{Text: "Hello"}}},
			width:    20,
			expected: 2,
		},
		{
			name:     "header wraps",
			block:    &HeaderBlock{Level: 1, Content: TextRun{{Text: "Hello World"}}},
			width:    5,
			expected: 3,
		},
		{
			name:     "zero width",
			block:    &HeaderBlock{Level: 1, Content: TextRun{{Text: "Hello"}}},
			width:    0,
			expected: 0,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			assert.Equal(t, tt.expected, tt.block.Height(tt.width))
		})
	}
}

func TestParagraphBlockHeight(t *testing.T) {
	tests := []struct {
		name     string
		block    *ParagraphBlock
		width    int
		expected int
	}{
		{
			name:     "simple paragraph",
			block:    &ParagraphBlock{Content: TextRun{{Text: "Hello"}}},
			width:    20,
			expected: 2,
		},
		{
			name:     "paragraph wraps",
			block:    &ParagraphBlock{Content: TextRun{{Text: "Hello World Test"}}},
			width:    5,
			expected: 4,
		},
		{
			name:     "zero width",
			block:    &ParagraphBlock{Content: TextRun{{Text: "Hello"}}},
			width:    0,
			expected: 0,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			assert.Equal(t, tt.expected, tt.block.Height(tt.width))
		})
	}
}

func TestCodeBlockHeight(t *testing.T) {
	tests := []struct {
		name     string
		block    *CodeBlock
		width    int
		expected int
	}{
		{
			name:     "single line",
			block:    &CodeBlock{Code: "code"},
			width:    20,
			expected: 2,
		},
		{
			name:     "multiple lines",
			block:    &CodeBlock{Code: "line1\nline2\nline3"},
			width:    20,
			expected: 4,
		},
		{
			name:     "trailing newline",
			block:    &CodeBlock{Code: "code\n"},
			width:    20,
			expected: 2,
		},
		{
			name:     "zero width",
			block:    &CodeBlock{Code: "code"},
			width:    0,
			expected: 0,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			assert.Equal(t, tt.expected, tt.block.Height(tt.width))
		})
	}
}

func TestListBlockHeight(t *testing.T) {
	tests := []struct {
		name     string
		block    *ListBlock
		width    int
		expected int
	}{
		{
			name: "simple list",
			block: &ListBlock{
				Items: []ListItem{
					{Content: TextRun{{Text: "Item 1"}}},
					{Content: TextRun{{Text: "Item 2"}}},
				},
			},
			width:    20,
			expected: 3,
		},
		{
			name: "nested list",
			block: &ListBlock{
				Items: []ListItem{
					{
						Content: TextRun{{Text: "Item 1"}},
						Nested: &ListBlock{
							Items: []ListItem{
								{Content: TextRun{{Text: "Nested"}}},
							},
						},
					},
				},
			},
			width:    20,
			expected: 4,
		},
		{
			name:     "zero width",
			block:    &ListBlock{Items: []ListItem{{Content: TextRun{{Text: "Item"}}}}},
			width:    0,
			expected: 0,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			assert.Equal(t, tt.expected, tt.block.Height(tt.width))
		})
	}
}

func TestBlockquoteBlockHeight(t *testing.T) {
	tests := []struct {
		name     string
		block    *BlockquoteBlock
		width    int
		expected int
	}{
		{
			name:     "simple blockquote",
			block:    &BlockquoteBlock{Content: []TextRun{{{Text: "Quote"}}}},
			width:    20,
			expected: 2,
		},
		{
			name: "nested blockquote",
			block: &BlockquoteBlock{
				Content: []TextRun{{{Text: "Outer"}}},
				Nested:  &BlockquoteBlock{Content: []TextRun{{{Text: "Inner"}}}},
			},
			width:    20,
			expected: 4,
		},
		{
			name:     "zero width",
			block:    &BlockquoteBlock{Content: []TextRun{{{Text: "Quote"}}}},
			width:    0,
			expected: 0,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			assert.Equal(t, tt.expected, tt.block.Height(tt.width))
		})
	}
}

func TestHorizontalRuleBlockHeight(t *testing.T) {
	block := &HorizontalRuleBlock{}
	assert.Equal(t, 2, block.Height(20))
	assert.Equal(t, 0, block.Height(0))
}

func TestTableBlockHeight(t *testing.T) {
	tests := []struct {
		name     string
		block    *TableBlock
		width    int
		expected int
	}{
		{
			name: "simple table",
			block: &TableBlock{
				Header: []TextRun{{{Text: "A"}}, {{Text: "B"}}},
				Rows:   [][]TextRun{{{{Text: "1"}}, {{Text: "2"}}}},
			},
			width:    20,
			expected: 6, // top + header + sep + 1 row + bottom + spacing
		},
		{
			name: "empty header",
			block: &TableBlock{
				Header: nil,
				Rows:   [][]TextRun{{{{Text: "1"}}, {{Text: "2"}}}},
			},
			width:    20,
			expected: 0,
		},
		{
			name: "zero width",
			block: &TableBlock{
				Header: []TextRun{{{Text: "A"}}},
			},
			width:    0,
			expected: 0,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			assert.Equal(t, tt.expected, tt.block.Height(tt.width))
		})
	}
}

func TestBlockRender(t *testing.T) {
	cfg := DefaultConfig()
	w := term.NewStringWriter(20, 10)

	tests := []struct {
		name     string
		block    Block
		expected int
	}{
		{
			name:     "header",
			block:    &HeaderBlock{Level: 1, Content: TextRun{{Text: "Title"}}},
			expected: 2,
		},
		{
			name:     "paragraph",
			block:    &ParagraphBlock{Content: TextRun{{Text: "Text"}}},
			expected: 2,
		},
		{
			name:     "code",
			block:    &CodeBlock{Code: "code"},
			expected: 2,
		},
		{
			name:     "hrule",
			block:    &HorizontalRuleBlock{},
			expected: 2,
		},
		{
			name:     "list",
			block:    &ListBlock{Items: []ListItem{{Content: TextRun{{Text: "Item"}}}}},
			expected: 2,
		},
		{
			name:     "blockquote",
			block:    &BlockquoteBlock{Content: []TextRun{{{Text: "Quote"}}}},
			expected: 2,
		},
		{
			name: "table",
			block: &TableBlock{
				Header: []TextRun{{{Text: "A"}}},
				Rows:   [][]TextRun{{{{Text: "1"}}}},
			},
			expected: 6, // top + header + sep + 1 row + bottom + spacing
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			require.NoError(t, w.Clear(term.Attributes{}))
			rendered := tt.block.Render(w, 0, 20, &cfg)
			assert.Equal(t, tt.expected, rendered)
		})
	}
}

func TestTextRunString(t *testing.T) {
	tests := []struct {
		name     string
		run      TextRun
		expected string
	}{
		{
			name:     "empty",
			run:      TextRun{},
			expected: "",
		},
		{
			name:     "single span",
			run:      TextRun{{Text: "hello"}},
			expected: "hello",
		},
		{
			name:     "multiple spans",
			run:      TextRun{{Text: "hello "}, {Text: "world"}},
			expected: "hello world",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			assert.Equal(t, tt.expected, tt.run.String())
		})
	}
}

func TestTextRunLen(t *testing.T) {
	tests := []struct {
		name     string
		run      TextRun
		expected int
	}{
		{
			name:     "empty",
			run:      TextRun{},
			expected: 0,
		},
		{
			name:     "single span",
			run:      TextRun{{Text: "hello"}},
			expected: 5,
		},
		{
			name:     "multiple spans",
			run:      TextRun{{Text: "hello"}, {Text: "world"}},
			expected: 10,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			assert.Equal(t, tt.expected, tt.run.Len())
		})
	}
}

func TestWrapTextRun(t *testing.T) {
	tests := []struct {
		name          string
		run           TextRun
		width         int
		expectedLines int
	}{
		{
			name:          "fits in width",
			run:           TextRun{{Text: "hello"}},
			width:         10,
			expectedLines: 1,
		},
		{
			name:          "wraps at word boundary",
			run:           TextRun{{Text: "hello world"}},
			width:         6,
			expectedLines: 2,
		},
		{
			name:          "breaks long word",
			run:           TextRun{{Text: "superlongword"}},
			width:         5,
			expectedLines: 3,
		},
		{
			name:          "zero width",
			run:           TextRun{{Text: "hello"}},
			width:         0,
			expectedLines: 0,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			lines := wrapTextRun(tt.run, tt.width)
			assert.Len(t, lines, tt.expectedLines)
		})
	}
}

func TestWrapTextRunPreservesSpaces(t *testing.T) {
	tests := []struct {
		name     string
		run      TextRun
		width    int
		expected string
	}{
		{
			name:     "single span with spaces",
			run:      TextRun{{Text: "hello world"}},
			width:    20,
			expected: "hello world",
		},
		{
			name: "multiple spans with trailing space",
			run: TextRun{
				{Text: "Create file in "},
				{Text: "component/", Style: StyleCode},
			},
			width:    80,
			expected: "Create file in component/",
		},
		{
			name: "multiple spans without explicit space",
			run: TextRun{
				{Text: "hello"},
				{Text: " "},
				{Text: "world"},
			},
			width:    80,
			expected: "hello world",
		},
		{
			name: "inline code in sentence",
			run: TextRun{
				{Text: "Implement "},
				{Text: "tui.Component", Style: StyleCode},
				{Text: " interface"},
			},
			width:    80,
			expected: "Implement tui.Component interface",
		},
		{
			name: "bold word in sentence",
			run: TextRun{
				{Text: "This is "},
				{Text: "bold", Style: StyleBold},
				{Text: " text"},
			},
			width:    80,
			expected: "This is bold text",
		},
		{
			name: "Development Workflow header",
			run: TextRun{
				{Text: "Development Workflow"},
			},
			width:    80,
			expected: "Development Workflow",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			lines := wrapTextRun(tt.run, tt.width)
			var buf strings.Builder
			for _, line := range lines {
				buf.WriteString(line.String())
			}
			assert.Equal(t, tt.expected, buf.String())
		})
	}
}

