package markdown

import (
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func TestParseHeaders(t *testing.T) {
	tests := []struct {
		name     string
		input    string
		expected int
		level    int
	}{
		{
			name:     "H1",
			input:    "# Header 1",
			expected: 1,
			level:    1,
		},
		{
			name:     "H2",
			input:    "## Header 2",
			expected: 1,
			level:    2,
		},
		{
			name:     "H3",
			input:    "### Header 3",
			expected: 1,
			level:    3,
		},
		{
			name:     "H4",
			input:    "#### Header 4",
			expected: 1,
			level:    4,
		},
		{
			name:     "H5",
			input:    "##### Header 5",
			expected: 1,
			level:    5,
		},
		{
			name:     "H6",
			input:    "###### Header 6",
			expected: 1,
			level:    6,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			blocks, err := Parse(tt.input)
			require.NoError(t, err)
			require.Len(t, blocks, tt.expected)

			header, ok := blocks[0].(*HeaderBlock)
			require.True(t, ok, "expected HeaderBlock")
			assert.Equal(t, tt.level, header.Level)
		})
	}
}

func TestParseParagraphs(t *testing.T) {
	tests := []struct {
		name     string
		input    string
		expected int
		text     string
	}{
		{
			name:     "simple paragraph",
			input:    "Hello world",
			expected: 1,
			text:     "Hello world",
		},
