func FuzzParse(f *testing.F) {
	f.Add("# Hello")
	f.Add("Hello **world**")
	f.Add("- item\n- item2")
	f.Add("```go\ncode\n```")
	f.Add("> quote")
	f.Add("---")
	f.Add("| a | b |\n|---|---|\n| 1 | 2 |")
	f.Add("")
	f.Add("# H1\n\n## H2\n\n### H3")
	f.Add("*italic* **bold** `code` ~~strike~~")
	f.Add("[link](http://example.com)")

