// Command mdview is a simple terminal markdown viewer.
//
// Usage:
//
//	mdview <file.md>
//
// Controls:
//   - Up/k:        Scroll up one line
//   - Down/j:      Scroll down one line
//   - Page Up:     Scroll up one page
//   - Page Down:   Scroll down one page
//   - Home/g:      Go to top
//   - End/G:       Go to bottom
//   - q/Esc:       Quit
package main

import (
	"fmt"
	"log"
	"os"

	"github.com/unstablebuild/rune-go-sdk/component/markdown"
	"github.com/unstablebuild/rune-go-sdk/term"
	"github.com/unstablebuild/rune-go-sdk/tui"
)

func main() {
	if len(os.Args) < 2 {
		fmt.Fprintf(os.Stderr, "Usage: %s <file.md>\n", os.Args[0])
		os.Exit(1)
	}

	content, err := os.ReadFile(os.Args[1])
	if err != nil {
		log.Fatalf("Failed to read file: %v", err)
	}

	viewer, err := NewViewer(string(content))
	if err != nil {
		log.Fatalf("Failed to parse markdown: %v", err)
	}

	if err := tui.Run(viewer); err != nil {
		log.Fatal(err)
	}
}

// Viewer wraps a markdown component with keyboard navigation.
type Viewer struct {
	md            *markdown.Component
	width, height int
}

// NewViewer creates a new markdown viewer for the given content.
func NewViewer(content string) (*Viewer, error) {
	md, err := markdown.New(content)
	if err != nil {
		return nil, err
	}
	return &Viewer{md: md}, nil
}

// Resize satisfies tui.Component.
func (v *Viewer) Resize(width, height int) {
	v.width, v.height = width, height
	v.md.Resize(width, height)
}

// Draw satisfies tui.Component.
func (v *Viewer) Draw(w term.Writer) {
	v.md.Draw(w)
}

// Handle satisfies tui.Handler.
func (v *Viewer) Handle(ev term.Event) (exit, handled bool) {
	if ev.Type != term.EventKey {
		return false, false
	}

	switch ev.Key {
	case term.KeyEsc:
		return true, true

	case term.KeyArrowUp:
		v.md.SeekUp()
		return false, true

	case term.KeyArrowDown:
		v.md.SeekDown()
		return false, true

	case term.KeyPgup:
		for range v.height {
			v.md.SeekUp()
		}
		return false, true

	case term.KeyPgdn:
		for range v.height {
			v.md.SeekDown()
		}
		return false, true

	case term.KeyHome:
		for v.md.SeekUp() {
		}
		return false, true

	case term.KeyEnd:
		for v.md.SeekDown() {
		}
		return false, true
	}

	switch ev.Ch {
	case 'q':
		return true, true

	case 'k':
		v.md.SeekUp()
		return false, true

	case 'j':
		v.md.SeekDown()
		return false, true

	case 'g':
		for v.md.SeekUp() {
		}
		return false, true

	case 'G':
		for v.md.SeekDown() {
		}
