func (t *tableBlock) renderCell(
	w term.Writer, x, y, width int, content textRun,
	align tableAlignment, isHeader bool,
) {
	text := content.String()
	textLen := len(text)
	if textLen > width {
		text = text[:width]
		textLen = width
	}

	var padding int
	switch align {
	case alignCenter:
		padding = (width - textLen) / 2
	case alignRight:
		padding = width - textLen
	}

	attr := t.cfg.Paragraph
	if isHeader {
		attr = t.cfg.Bold
	}

	spIdx := 0
	runeIdx := 0
	for i, r := range text {
		cellX := x + padding + i
		cellAttr := attr
		if spIdx < len(content) {
			sp := content[spIdx]
			if !isHeader {
				cellAttr = resolveStyle(sp.style, t.cfg)
			}
			runeIdx++
			if runeIdx >= len(sp.text) {
				spIdx++
				runeIdx = 0
			}
		}
		w.SetCell(term.Coordinates{X: cellX, Y: y}, term.Cell{
			Ch:         r,
			Width:      1,
			Attributes: cellAttr,
		})
	}
}

